type HtmlTagToken = {
  end: number;
  tagName: string | null;
  closing: boolean;
  selfClosing: boolean;
};

function escapeRegExp(value: string) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function findHtmlTagTokenEnd(content: string, start: number) {
  let quote: '"' | "'" | null = null;

  for (let index = start + 1; index < content.length; index += 1) {
    const char = content[index];
    if (quote) {
      if (char === quote && content[index - 1] !== "\\") quote = null;
      continue;
    }

    if (char === '"' || char === "'") {
      quote = char;
      continue;
    }

    if (char === ">") return index + 1;
  }

  return -1;
}

function readHtmlTagToken(content: string, start: number): HtmlTagToken | null {
  if (content[start] !== "<") return null;

  if (content.startsWith("<!--", start)) {
    const commentEnd = content.indexOf("-->", start + 4);
    return {
      end: commentEnd >= 0 ? commentEnd + 3 : content.length,
      tagName: null,
      closing: false,
      selfClosing: true,
    };
  }

  const end = findHtmlTagTokenEnd(content, start);
  if (end < 0) return null;

  const rawTag = content.slice(start, end);
  const tagMatch = /^<\s*\/?\s*([A-Za-z][\w:-]*)/.exec(rawTag);
  const tagName = tagMatch?.[1]?.toLowerCase() ?? null;
  const closing = /^<\s*\//.test(rawTag);
  const selfClosing =
    !closing && ((!!tagName && htmlVoidTags.has(tagName)) || /\/\s*>$/.test(rawTag));

  return {
    end,
    tagName,
    closing,
    selfClosing,
  };
}

function findHtmlClosingTagEnd(content: string, start: number, tagName: string) {
  const closePattern = new RegExp(`</\\s*${escapeRegExp(tagName)}\\s*>`, "i");
  const match = closePattern.exec(content.slice(start));
  return match ? start + match.index + match[0].length : -1;
}

function findMatchingHtmlBlockEnd(content: string, start: number, rootTagName: string) {
  if (htmlRawTextTags.has(rootTagName)) {
    const rawTextEnd = findHtmlClosingTagEnd(content, start, rootTagName);
    return rawTextEnd >= 0 ? rawTextEnd : -1;
  }

  let depth = 0;
  let cursor = start;

  while (cursor < content.length) {
    const nextTagStart = content.indexOf("<", cursor);
    if (nextTagStart < 0) return -1;

    const token = readHtmlTagToken(content, nextTagStart);
    if (!token) {
      cursor = nextTagStart + 1;
      continue;
    }

    const tokenTagName = token.tagName;
    if (tokenTagName === rootTagName) {
      if (token.closing) {
        depth -= 1;
        if (depth <= 0) return token.end;
      } else if (!token.selfClosing) {
        depth += 1;
      }
    } else if (tokenTagName && htmlRawTextTags.has(tokenTagName) && !token.closing) {
      const rawTextEnd = findHtmlClosingTagEnd(content, token.end, tokenTagName);
      if (rawTextEnd >= 0) {
        cursor = rawTextEnd;
        continue;
      }
    }

    cursor = token.end;
  }

  return -1;
}

type RecoverableHtmlBlockBoundary = {
  contentEnd: number;
  resumeEnd: number;
};

function findRecoverableHtmlBlockBoundary(
  content: string,
  start: number,
  rootTagName: string,
  allowEmptyTrailingContent = false,
): RecoverableHtmlBlockBoundary | null {
  const openTagDepths = new Map<string, number>();
  let rootDepth = 0;
  let cursor = start;
  let lastRootMarkupEnd = -1;
  const rememberRootMarkupEnd = (end: number) => {
    if (
      rootDepth === 1 &&
      Array.from(openTagDepths.entries()).every(
        ([tagName, depth]) => tagName === rootTagName || depth === 0,
      )
    ) {
      lastRootMarkupEnd = end;
    }
  };

  while (cursor < content.length) {
    const nextTagStart = content.indexOf("<", cursor);
    if (nextTagStart < 0) break;

    const token = readHtmlTagToken(content, nextTagStart);
    if (!token) {
      cursor = nextTagStart + 1;
      continue;
    }

    const tokenTagName = token.tagName;
    if (!tokenTagName) {
      cursor = token.end;
      continue;
    }

    if (token.closing) {
      const openDepth = openTagDepths.get(tokenTagName) ?? 0;
      if (
        rootDepth === 1 &&
        openDepth === 0 &&
        tokenTagName !== rootTagName &&
        !htmlStandardTags.has(tokenTagName)
      ) {
        return { contentEnd: nextTagStart, resumeEnd: token.end };
      }

      if (openDepth > 0) {
        openTagDepths.set(tokenTagName, openDepth - 1);
      }
      if (tokenTagName === rootTagName) {
        rootDepth -= 1;
        if (rootDepth <= 0) return null;
      }
      rememberRootMarkupEnd(token.end);
      cursor = token.end;
      continue;
    }

    if (token.selfClosing) {
      rememberRootMarkupEnd(token.end);
      cursor = token.end;
      continue;
    }

    openTagDepths.set(tokenTagName, (openTagDepths.get(tokenTagName) ?? 0) + 1);
    if (tokenTagName === rootTagName) rootDepth += 1;

    if (htmlRawTextTags.has(tokenTagName)) {
      const rawTextEnd = findHtmlClosingTagEnd(content, token.end, tokenTagName);
      if (rawTextEnd < 0) return null;
      openTagDepths.set(tokenTagName, 0);
      rememberRootMarkupEnd(rawTextEnd);
      cursor = rawTextEnd;
      continue;
    }

    rememberRootMarkupEnd(token.end);
    cursor = token.end;
  }

  if (
    lastRootMarkupEnd > start &&
    (allowEmptyTrailingContent || content.slice(lastRootMarkupEnd).trim())
  ) {
    return { contentEnd: lastRootMarkupEnd, resumeEnd: lastRootMarkupEnd };
  }

  return null;
}

function stripStandaloneOrphanCustomClosingTags(content: string) {
  return content.replace(
    /(^|\n)([ \t]*)<\/\s*([A-Za-z][\w:-]*)\s*>([ \t]*)(?=\n|$)/g,
    (match, lineStart: string, _indentation: string, rawTagName: string) => {
      const tagName = rawTagName.toLowerCase();
      if (htmlStandardTags.has(tagName)) return match;
      const openingTagPattern = new RegExp(
        `<\\s*${escapeRegExp(tagName)}(?=[\\s>/])`,
        "i",
      );
      if (openingTagPattern.test(content)) return match;
      return lineStart;
    },
  );
}

type OrphanCustomClosingTagBoundary = {
  start: number;
  end: number;
  tagName: string;
};

type ChatFenceBlock = {
  openStart: number;
  contentStart: number;
  contentEnd: number;
  closeEnd: number;
  language: string;
};

const wrappedChatContentStyle = [
  '<style data-renge-wrapped-chat-content="true">',
  '[data-renge-wrapped-text="true"]{position:relative;z-index:1;white-space:normal;}',
  '[data-renge-wrapped-text="true"] .renge-wrapped-paragraph{white-space:pre-wrap;margin:0 0 1em;}',
  '[data-renge-wrapped-text="true"] blockquote{margin:0 0 1em;padding-left:1em;border-left:3px solid currentColor;opacity:.9;}',
  '[data-renge-wrapped-text="true"] ul,[data-renge-wrapped-text="true"] ol{margin:0 0 1em;padding-left:1.8em;}',
  '[data-renge-wrapped-text="true"] pre{overflow:auto;white-space:pre-wrap;}',
  '[data-renge-wrapped-text="true"] img{max-width:100%;height:auto;}',
  '</style>',
].join("");

function escapeChatHtmlText(value: string) {
  return value
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

function escapeChatHtmlAttribute(value: string) {
  return escapeChatHtmlText(value)
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function renderWrappedInlineMarkdown(content: string) {
  const inlinePattern =
    /`(?<code>[^`]+)`|!\[(?<imageAlt>[^\]]*)\]\s*\(\s*(?<imageUrl>[^)\s]+)\s*\)|\[(?<linkText>[^\]]+)\]\s*\(\s*(?<linkUrl>[^)\s]+)\s*\)|\*\*(?<doubleAsterisk>[^*]+)\*\*|__(?<doubleUnderscore>[^_]+)__|~~(?<deleted>[^~]+)~~|\*(?<asteriskEm>[^*\n]+)\*|_(?<underscoreEm>[^_\n]+)_/g;
  let output = "";
  let cursor = 0;
  let match: RegExpExecArray | null;

  while ((match = inlinePattern.exec(content))) {
    if (match.index > cursor) {
      output += escapeChatHtmlText(content.slice(cursor, match.index));
    }
    const groups = match.groups ?? {};
    if (groups.code !== undefined) {
      output += `<code>${escapeChatHtmlText(groups.code)}</code>`;
    } else if (groups.imageAlt !== undefined && groups.imageUrl !== undefined) {
      if (/^(?:https?:|data:image\/)/i.test(groups.imageUrl)) {
        output += `<img alt="${escapeChatHtmlAttribute(groups.imageAlt || "图片")}" loading="lazy" src="${escapeChatHtmlAttribute(groups.imageUrl)}" />`;
      } else {
        output += escapeChatHtmlText(match[0]);
      }
    } else if (groups.linkText !== undefined && groups.linkUrl !== undefined) {
      if (/^(?:https?:|mailto:|#|\/)/i.test(groups.linkUrl)) {
        output += `<a href="${escapeChatHtmlAttribute(groups.linkUrl)}" rel="noreferrer" target="_blank">${renderWrappedInlineMarkdown(groups.linkText)}</a>`;
      } else {
        output += escapeChatHtmlText(match[0]);
      }
    } else if (groups.doubleAsterisk !== undefined) {
      output += `<strong>${renderWrappedInlineMarkdown(groups.doubleAsterisk)}</strong>`;
    } else if (groups.doubleUnderscore !== undefined) {
      output += `<strong>${renderWrappedInlineMarkdown(groups.doubleUnderscore)}</strong>`;
    } else if (groups.deleted !== undefined) {
      output += `<del>${escapeChatHtmlText(groups.deleted)}</del>`;
    } else if (groups.asteriskEm !== undefined) {
      output += `<em>${renderWrappedInlineMarkdown(groups.asteriskEm)}</em>`;
    } else if (groups.underscoreEm !== undefined) {
      output += `<em>${escapeChatHtmlText(groups.underscoreEm)}</em>`;
    }
    cursor = match.index + match[0].length;
  }

  if (cursor < content.length) output += escapeChatHtmlText(content.slice(cursor));
  return output;
}

function renderWrappedMarkdownBlocks(content: string) {
  const normalized = content.replace(/\r\n/g, "\n").trim();
  if (!normalized) return "";

  return normalized
    .split(/\n{2,}/)
    .map((block) => {
      const lines = block.split("\n");
      const trimmedLines = lines.map((line) => line.trim());
      const headingMatch = /^(#{1,6})\s+(.+)$/.exec(trimmedLines[0]);
      if (headingMatch && lines.length === 1) {
        const level = Math.min(6, headingMatch[1].length);
        return `<h${level}>${renderWrappedInlineMarkdown(headingMatch[2])}</h${level}>`;
      }
      if (trimmedLines.every((line) => /^[-*+]\s+/.test(line))) {
        return `<ul>${trimmedLines
          .map((line) => `<li>${renderWrappedInlineMarkdown(line.replace(/^[-*+]\s+/, ""))}</li>`)
          .join("")}</ul>`;
      }
      if (trimmedLines.every((line) => /^\d+\.\s+/.test(line))) {
        return `<ol>${trimmedLines
          .map((line) => `<li>${renderWrappedInlineMarkdown(line.replace(/^\d+\.\s+/, ""))}</li>`)
          .join("")}</ol>`;
      }
      if (trimmedLines.every((line) => line.startsWith(">"))) {
        return `<blockquote>${trimmedLines
          .map((line) => renderWrappedInlineMarkdown(line.replace(/^>\s?/, "")))
          .join("<br />")}</blockquote>`;
      }
      return `<p class="mes_text renge-wrapped-paragraph">${lines
        .map((line) => renderWrappedInlineMarkdown(line))
        .join("<br />")}</p>`;
    })
    .join("");
}

function renderWrappedMixedChatContent(content: string) {
  const segments = splitEmbeddedHtmlBlocks(content);
  return segments
    .map((segment) =>
      segment.type === "html"
        ? segment.content
        : renderWrappedMarkdownBlocks(segment.content),
    )
    .join("");
}

function encodeEmbeddedHtmlDocument(content: string) {
  const bytes = new TextEncoder().encode(content);
  const buffer = bytes.buffer.slice(
    bytes.byteOffset,
    bytes.byteOffset + bytes.byteLength,
  ) as ArrayBuffer;
  return arrayBufferToBase64(buffer);
}

function decodeEmbeddedHtmlDocument(content: string) {
  return new TextDecoder().decode(base64ToArrayBuffer(content));
}

function createEmbeddedHtmlDocumentMarker(content: string) {
  return `<script type="application/x-renge-embedded-html">${encodeEmbeddedHtmlDocument(content)}</script>`;
}

function findStandaloneOrphanCustomClosingTag(
  content: string,
  searchStart = 0,
): OrphanCustomClosingTagBoundary | null {
  const closingPattern = /(^|\n)([ \t]*)<\/\s*([A-Za-z][\w:-]*)\s*>[ \t]*(?=\n|$)/g;
  closingPattern.lastIndex = searchStart;
  let match: RegExpExecArray | null;

  while ((match = closingPattern.exec(content))) {
    const tagName = match[3].toLowerCase();
    if (htmlStandardTags.has(tagName)) continue;
    const openingTagPattern = new RegExp(
      `<\\s*${escapeRegExp(tagName)}(?=[\\s>/])`,
      "i",
    );
    if (openingTagPattern.test(content)) continue;
    return {
      start: match.index + match[1].length + match[2].length,
      end: match.index + match[0].length,
      tagName,
    };
  }

  return null;
}

function findNextChatFence(content: string, searchStart: number): ChatFenceBlock | null {
  const openingPattern = /^[ \t]*```([A-Za-z0-9_-]*)[^\r\n]*(?:\r?\n|$)/gm;
  openingPattern.lastIndex = searchStart;
  const openingMatch = openingPattern.exec(content);
  if (!openingMatch) return null;

  const language = openingMatch[1].toLowerCase();
  const contentStart = openingMatch.index + openingMatch[0].length;
  const closingPattern = /^[ \t]*```[ \t]*(?:\r?\n|$)/gm;
  closingPattern.lastIndex = contentStart;
  let closingMatch: RegExpExecArray | null;

  while ((closingMatch = closingPattern.exec(content))) {
    const candidateContent = content.slice(contentStart, closingMatch.index).trimEnd();
    const fullHtmlDocument = /^(?:<!doctype\s+html|<html[\s>])/i.test(
      candidateContent.trimStart(),
    );
    if (language === "html" && fullHtmlDocument && !/<\/html>\s*$/i.test(candidateContent)) {
      continue;
    }
    return {
      openStart: openingMatch.index,
      contentStart,
      contentEnd: closingMatch.index,
      closeEnd: closingMatch.index + closingMatch[0].length,
      language,
    };
  }

  return null;
}

function composeRecoverableHtmlWrapper(
  wrapperContent: string,
  rootTagName: string,
) {
  let cursor = 0;
  let firstPlainSegment = true;
  let foundRootMarkup = false;
  let output = "";

  const appendPlainSegment = (plainContent: string) => {
    if (!firstPlainSegment) {
      output += renderWrappedMixedChatContent(plainContent);
      return true;
    }

    firstPlainSegment = false;
    const boundary = findRecoverableHtmlBlockBoundary(
      plainContent,
      0,
      rootTagName,
      true,
    );
    if (!boundary) return false;
    output += plainContent.slice(0, boundary.contentEnd);
    output += wrappedChatContentStyle;
    output += '<div data-renge-wrapped-text="true">';
    output += renderWrappedMixedChatContent(plainContent.slice(boundary.resumeEnd));
    foundRootMarkup = true;
    return true;
  };

  while (cursor < wrapperContent.length) {
    const fence = findNextChatFence(wrapperContent, cursor);
    if (!fence) break;
    if (!appendPlainSegment(wrapperContent.slice(cursor, fence.openStart))) return null;
    const fenceContent = wrapperContent.slice(fence.contentStart, fence.contentEnd).trim();
    if (htmlLanguages.has(fence.language) || looksLikeRenderableHtml(fenceContent)) {
      output += createEmbeddedHtmlDocumentMarker(fenceContent);
    } else {
      output += `<pre><code>${escapeChatHtmlText(fenceContent)}</code></pre>`;
    }
    cursor = fence.closeEnd;
  }

  if (!appendPlainSegment(wrapperContent.slice(cursor))) return null;
  if (!foundRootMarkup) return null;
  output += `</div></${rootTagName}>`;
  return output;
}

function parseRecoverableHtmlWrapper(
  content: string,
  audioRenderingEnabled: boolean,
): ChatContentPart[] | null {
  const orphanClosingTag = findStandaloneOrphanCustomClosingTag(content);
  if (!orphanClosingTag) return null;

  const htmlStartPattern = /(^|\n)([ \t]*)<([A-Za-z][\w:-]*)(?=[\s>/])/g;
  let rootMatch: RegExpExecArray | null;
  let blockStart = -1;
  let rootTagName = "";
  while ((rootMatch = htmlStartPattern.exec(content))) {
    const candidateStart = rootMatch.index + rootMatch[1].length + rootMatch[2].length;
    const candidateTagName = rootMatch[3].toLowerCase();
    if (candidateStart >= orphanClosingTag.start) break;
    if (!htmlBlockRootTags.has(candidateTagName)) continue;
    blockStart = candidateStart;
    rootTagName = candidateTagName;
    break;
  }
  if (blockStart < 0 || !rootTagName) return null;

  const wrapperContent = content.slice(blockStart, orphanClosingTag.start);
  const composedWrapper = composeRecoverableHtmlWrapper(wrapperContent, rootTagName);
  if (!composedWrapper) return null;

  const parts: ChatContentPart[] = [];
  const leadingContent = content.slice(0, blockStart);
  if (leadingContent.trim()) {
    parts.push(...parseGenericChatContentParts(leadingContent, audioRenderingEnabled));
  }
  parts.push({
    type: "code",
    content: composedWrapper,
    language: "html",
    executable: false,
  });
  const trailingContent = content.slice(orphanClosingTag.end);
  const trailingParts =
    parseFencedHtmlDocuments(trailingContent, audioRenderingEnabled) ??
    parseGenericChatContentParts(trailingContent, audioRenderingEnabled);
  parts.push(...trailingParts);
  return parts.filter(
    (part) => part.type === "audio" || part.type === "liveStream" || part.content.length > 0,
  );
}

function findHtmlDocumentEnd(content: string, start: number) {
  const htmlClosePattern = /<\/\s*html\s*>/i;
  const htmlCloseMatch = htmlClosePattern.exec(content.slice(start));
  if (htmlCloseMatch) return start + htmlCloseMatch.index + htmlCloseMatch[0].length;

  const bodyClosePattern = /<\/\s*body\s*>/i;
  const bodyCloseMatch = bodyClosePattern.exec(content.slice(start));
  if (bodyCloseMatch) return start + bodyCloseMatch.index + bodyCloseMatch[0].length;

  return content.length;
}

function pushPlainChatHtmlSegment(
  segments: PlainChatHtmlSegment[],
  type: PlainChatHtmlSegment["type"],
  content: string,
) {
  if (!content) return;
  const previousSegment = segments[segments.length - 1];
  if (previousSegment?.type === type) {
    previousSegment.content += content;
    return;
  }
  segments.push({ type, content });
}

function splitEmbeddedHtmlBlocks(content: string): PlainChatHtmlSegment[] {
  const segments: PlainChatHtmlSegment[] = [];
  const htmlStartPattern =
    /(^|\n|(?=<!doctype\s+html\b)|(?=<html(?=[\s>/])))([ \t]*)(<!doctype\s+html\b|<([A-Za-z][\w:-]*)(?=[\s>/]))/gi;
  let cursor = 0;
  let searchCursor = 0;

  while (searchCursor < content.length) {
    htmlStartPattern.lastIndex = searchCursor;
    const match = htmlStartPattern.exec(content);

    if (!match) {
      pushPlainChatHtmlSegment(segments, "text", content.slice(cursor));
      break;
    }

    const blockStart = match.index + match[1].length + match[2].length;
    const marker = match[3].toLowerCase();
    const rootTagName = match[4]?.toLowerCase() ?? null;
    let blockEnd = -1;

    if (marker.startsWith("<!doctype")) {
      blockEnd = findHtmlDocumentEnd(content, blockStart);
    } else if (rootTagName && htmlBlockRootTags.has(rootTagName)) {
      blockEnd = findMatchingHtmlBlockEnd(content, blockStart, rootTagName);
    }

    let resumeEnd = blockEnd;
    let syntheticClosingTag = "";
    if (blockEnd <= blockStart && rootTagName && htmlBlockRootTags.has(rootTagName)) {
      const recoverableBoundary = findRecoverableHtmlBlockBoundary(
        content,
        blockStart,
        rootTagName,
      );
      if (recoverableBoundary) {
        blockEnd = recoverableBoundary.contentEnd;
        resumeEnd = recoverableBoundary.resumeEnd;
        syntheticClosingTag = `</${rootTagName}>`;
      }
    }

    if (blockEnd <= blockStart) {
      searchCursor = blockStart + 1;
      continue;
    }

    let trailingCursor = blockEnd;
    while (trailingCursor < content.length) {
      const whitespace = /^\s*/.exec(content.slice(trailingCursor))?.[0] ?? "";
      const trailingTagStart = trailingCursor + whitespace.length;
      const trailingToken = readHtmlTagToken(content, trailingTagStart);
      if (
        !trailingToken?.tagName ||
        trailingToken.closing ||
        !htmlRawTextTags.has(trailingToken.tagName)
      ) {
        break;
      }
      const trailingBlockEnd = findMatchingHtmlBlockEnd(
        content,
        trailingTagStart,
        trailingToken.tagName,
      );
      if (trailingBlockEnd <= trailingTagStart) break;
      blockEnd = trailingBlockEnd;
      trailingCursor = trailingBlockEnd;
    }
    resumeEnd = Math.max(resumeEnd, blockEnd);

    const htmlBlock = `${content.slice(blockStart, blockEnd)}${syntheticClosingTag}`;
    if (!looksLikeRenderableHtml(htmlBlock)) {
      searchCursor = blockStart + 1;
      continue;
    }

    if (blockStart > cursor) {
      pushPlainChatHtmlSegment(segments, "text", content.slice(cursor, blockStart));
    }
    pushPlainChatHtmlSegment(segments, "html", htmlBlock);
    cursor = resumeEnd;
    searchCursor = resumeEnd;
  }

  return segments.length > 0 ? segments : [{ type: "text", content }];
}

function parsePlainChatContent(
  content: string,
  audioRenderingEnabled: boolean,
): ChatContentPart[] {
  const parts: ChatContentPart[] = [];
  // 修复 LLM 偶尔把 ![alt](url) 写错的几种情况：
  //   1. ![alt]\n  (url)        → ![alt](url)
  //   2. alt](url) 缺前导 ![    → ![alt](url)
  //   3. alt](\n url \n)         → ![alt](url)
  let normalized = content.replace(/\r\n/g, "\n");
  // 隐藏服务端为识图 MCP 注入的本地路径注释（不影响发回模型的 message.content 原文）
  normalized = stripHiddenImageAnnotations(normalized);
  // 酒馆角色卡常用正则只替换 XML 风格包装标签的开头，并把原闭标签留在消息里。
  // 这些孤立闭标签不应作为正文显示；真正的 HTML 容器会在下方提取时补齐。
  normalized = stripStandaloneOrphanCustomClosingTags(normalized);
  // 合并 \"]\" 与 \"(\" 之间的换行与空白
  normalized = normalized.replace(/\](\s*\n\s*)+\(/g, "](");
  // 合并 \"(\" 与 url 之间的空白/换行
  normalized = normalized.replace(/\(\s*\n\s*(https?:\/\/|data:image\/)/g, "($1");
  // 合并 url 与 \")\" 之间的空白/换行
  normalized = normalized.replace(/((?:https?:\/\/|data:image\/)\S+?)\s*\n\s*\)/g, "$1)");
  // 给独立的 \"alt](image-url)\" 自动补上前导 \"![\"
  normalized = normalized.replace(
    /(^|[\s\u3000])([^\s!\[\]\n][^\[\]\n]*?)\]\((https?:\/\/\S+?\.(?:png|jpe?g|webp|gif)(?:\?\S*)?|data:image\/[^)]+)\)/g,
    "$1![$2]($3)",
  );

  const plainSegments = splitEmbeddedHtmlBlocks(normalized);
  if (plainSegments.some((segment) => segment.type === "html")) {
    for (const segment of plainSegments) {
      if (segment.type === "html") {
        parts.push({
          type: "code",
          content: segment.content.trim(),
          language: "html",
          executable: false,
        });
        continue;
      }

      parts.push(...parsePlainChatContent(segment.content, audioRenderingEnabled));
    }
    return parts;
  }

  if (audioRenderingEnabled) {
    const audioSegments = splitChatAudioEmbeds(normalized);
    if (audioSegments.some((segment) => segment.type === "audio")) {
      for (const segment of audioSegments) {
        if (segment.type === "audio") {
          parts.push(segment);
        } else {
          parts.push(...parsePlainChatContent(segment.content, audioRenderingEnabled));
        }
      }
      return parts;
    }
  }

  const liveStreamSegments = splitChatLiveStreamEmbeds(normalized);
  if (liveStreamSegments.some((segment) => segment.type === "liveStream")) {
    for (const segment of liveStreamSegments) {
      if (segment.type === "liveStream") {
        parts.push(segment);
      } else {
        parts.push(...parsePlainChatContent(segment.content, audioRenderingEnabled));
      }
    }
    return parts;
  }

  const lines = normalized.split("\n");
  let textBuffer: string[] = [];
  let codeBuffer: string[] = [];
  let codeMode: "command" | "code" | null = null;

  const flushText = () => {
    if (textBuffer.length === 0) return;
    appendTextPart(parts, textBuffer.join("\n"));
    textBuffer = [];
  };

  const flushCode = () => {
    if (codeBuffer.length === 0 || !codeMode) return;
    parts.push({
      type: "code",
      content: codeBuffer.join("\n"),
      language: codeMode === "command" ? "shell" : "text",
      executable: codeMode === "command" && isExecutableCommandBlock(codeBuffer.join("\n")),
    });
    codeBuffer = [];
    codeMode = null;
  };

  for (const line of lines) {
    const trimmedLine = line.trim();
    const nextMode = isRunnableCommandLine(trimmedLine)
      ? "command"
      : isStandaloneCodeLine(trimmedLine)
        ? "code"
        : null;

    if (nextMode) {
      flushText();
      if (codeMode && codeMode !== nextMode) flushCode();
      codeMode = nextMode;
      codeBuffer.push(trimmedLine);
      continue;
    }

    flushCode();
    textBuffer.push(line);
  }

  flushCode();
  flushText();
  return parts;
}

type FencedHtmlDocumentNode = {
  openStart: number;
  contentStart: number;
  contentEnd: number;
  closeEnd: number;
  children: FencedHtmlDocumentNode[];
};

function getFencedHtmlDocumentContent(content: string, node: FencedHtmlDocumentNode) {
  let documentContent = content.slice(node.contentStart, node.contentEnd);
  [...node.children].reverse().forEach((child) => {
    const childStart = Math.max(0, child.openStart - node.contentStart);
    const childEnd = Math.max(childStart, child.closeEnd - node.contentStart);
    documentContent =
      documentContent.slice(0, childStart) + documentContent.slice(childEnd);
  });
  return documentContent.trim();
}

function appendFencedHtmlDocumentParts(
  parts: ChatContentPart[],
  content: string,
  node: FencedHtmlDocumentNode,
) {
  const documentContent = getFencedHtmlDocumentContent(content, node);
  if (looksLikeRenderableHtml(documentContent)) {
    parts.push({
      type: "code",
      content: documentContent,
      language: "html",
      executable: false,
    });
  }
}

function parseGenericChatContentParts(
  content: string,
  audioRenderingEnabled: boolean,
): ChatContentPart[] {
  const parts: ChatContentPart[] = [];
  const fencePattern =
    /^[ \t]*```([A-Za-z0-9_-]*)[ \t]*\r?\n([\s\S]*?)^[ \t]*```[ \t]*\r?$/gm;
  let cursor = 0;
  let match: RegExpExecArray | null;

  while ((match = fencePattern.exec(content))) {
    const plainContent = content.slice(cursor, match.index);
    parts.push(...parsePlainChatContent(plainContent, audioRenderingEnabled));

    const language = (match[1] || "text").toLowerCase();
    const codeContent = match[2].replace(/^\n|\n$/g, "");
    const executable = shellLanguages.has(language) && isExecutableCommandBlock(codeContent);
    parts.push({
      type: "code",
      content: codeContent,
      language,
      executable,
    });
    cursor = match.index + match[0].length;
  }

  parts.push(...parsePlainChatContent(content.slice(cursor), audioRenderingEnabled));
  return parts.filter(
    (part) => part.type === "audio" || part.type === "liveStream" || part.content.length > 0,
  );
}

function parseFencedHtmlDocuments(
  content: string,
  audioRenderingEnabled: boolean,
): ChatContentPart[] | null {
  const fenceLinePattern = /^[ \t]*```([A-Za-z0-9_-]*)([^\r\n]*)(?:\r?\n|$)/gim;
  const roots: FencedHtmlDocumentNode[] = [];
  const stack: FencedHtmlDocumentNode[] = [];
  let match: RegExpExecArray | null;

  while ((match = fenceLinePattern.exec(content))) {
    const language = match[1].toLowerCase();
    const trailingContent = match[2].trim();
    const backtickOffset = match[0].indexOf("```");
    const tokenStart = match.index + Math.max(0, backtickOffset);

    if (language === "html" && !trailingContent) {
      const node: FencedHtmlDocumentNode = {
        openStart: match.index,
        contentStart: match.index + match[0].length,
        contentEnd: -1,
        closeEnd: -1,
        children: [],
      };
      const parent = stack[stack.length - 1];
      if (parent) parent.children.push(node);
      else roots.push(node);
      stack.push(node);
      continue;
    }

    if (language || stack.length === 0) continue;
    const currentNode = stack[stack.length - 1];
    const candidateContent = content.slice(currentNode.contentStart, tokenStart).trimEnd();
    if (!/<\/html>\s*$/i.test(candidateContent)) continue;

    currentNode.contentEnd = tokenStart;
    currentNode.closeEnd = tokenStart + 3;
    stack.pop();
  }

  if (roots.length === 0 || stack.length > 0 || roots.some((node) => node.closeEnd < 0)) {
    return null;
  }

  const parts: ChatContentPart[] = [];
  let cursor = 0;
  roots.forEach((root) => {
    if (root.openStart > cursor) {
      parts.push(
        ...parseGenericChatContentParts(
          content.slice(cursor, root.openStart),
          audioRenderingEnabled,
        ),
      );
    }
    appendFencedHtmlDocumentParts(parts, content, root);
    cursor = root.closeEnd;
  });
  parts.push(
    ...parseGenericChatContentParts(content.slice(cursor), audioRenderingEnabled),
  );
  return parts.filter(
    (part) => part.type === "audio" || part.type === "liveStream" || part.content.length > 0,
  );
}

function parseChatContentParts(
  content: string,
  audioRenderingEnabled: boolean,
): ChatContentPart[] {
  return (
    parseRecoverableHtmlWrapper(content, audioRenderingEnabled) ??
    parseFencedHtmlDocuments(content, audioRenderingEnabled) ??
    parseGenericChatContentParts(content, audioRenderingEnabled)
  );
}

function looksLikeRenderableHtml(content: string) {
  const trimmedContent = content.trim();
  if (!trimmedContent) return false;
  if (/<!doctype\s+html|<html[\s>]|<head[\s>]|<body[\s>]|<style[\s>]/i.test(trimmedContent)) {
    return true;
  }
  return /<[a-z][\w:-]*(?:\s[^>]*)?>[\s\S]*<\/[a-z][\w:-]*>/i.test(trimmedContent);
}

function looksLikeStandaloneRenderableHtml(content: string) {
  const trimmedContent = content.trim();
  if (!looksLikeRenderableHtml(trimmedContent)) return false;
  if (/^(?:<!doctype\s+html|<html[\s>]|<head[\s>]|<body[\s>]|<style[\s>])/i.test(trimmedContent)) {
    return true;
  }
  return (
    /^<[a-z][\w:-]*(?:\s[^>]*)?>/i.test(trimmedContent) &&
    /<\/[a-z][\w:-]*>\s*$/i.test(trimmedContent)
  );
}

function shouldRenderHtmlCodePart(part: Extract<ChatContentPart, { type: "code" }>) {
  return (
    htmlLanguages.has(part.language) ||
    (part.language === "text" && looksLikeRenderableHtml(part.content))
  );
}

function getHtmlPreviewContentRevision(content: string) {
  const length = content.length;
  if (length === 0) return "0-0";

  let hash = 2166136261;
  const sampleStep = Math.max(1, Math.floor(length / 4096));
  for (let index = 0; index < length; index += sampleStep) {
    hash ^= content.charCodeAt(index);
    hash = Math.imul(hash, 16777619);
  }
  hash ^= content.charCodeAt(length - 1);
  hash = Math.imul(hash, 16777619);
  return `${length}-${(hash >>> 0).toString(36)}`;
}

function buildHtmlPreviewScript(previewId: string, heavyContent: boolean) {
  const previewIdLiteral = JSON.stringify(previewId);
  const messageTypeLiteral = JSON.stringify(HTML_PREVIEW_RESIZE_MESSAGE);
  const remeasureMessageTypeLiteral = JSON.stringify(HTML_PREVIEW_REMEASURE_MESSAGE);

  return [
    '<script data-renge-html-preview="true">',
    "(() => {",
    `const previewId = ${previewIdLiteral};`,
    `const messageType = ${messageTypeLiteral};`,
    `const remeasureMessageType = ${remeasureMessageTypeLiteral};`,
    `const maxHeight = ${HTML_PREVIEW_MAX_HEIGHT};`,
    `const heavyContent = ${heavyContent ? "true" : "false"};`,
    "const defaultHeight = 420;",
    `const minHeight = ${HTML_PREVIEW_MEASURED_MIN_HEIGHT};`,
    "const padding = 12;",
    "let rafId = 0;",
    "let rafFallbackTimer = 0;",
    "let heavyPostTimer = 0;",
    "let lastHeight = 0;",
    "let lastExpandedDetailsHeight = 0;",
    "let lastExpandedDetailsState = false;",
    "let lastMeasuredContentHeight = 0;",
    "let lastMeasuredViewportHeight = 0;",
    "let currentScale = 1;",
    "let naturalLayout = null;",
    "let naturalLayoutDirty = true;",
    "let forceNextPost = false;",
    "let lastViewportWidth = 0;",
    "const clampHeight = (height) => {",
    "  const numericHeight = Number(height);",
    "  if (!Number.isFinite(numericHeight)) return defaultHeight;",
    "  return Math.max(minHeight, Math.min(Math.ceil(numericHeight), maxHeight));",
    "};",
    "const setScale = (scale) => {",
    "  if (Math.abs(currentScale - scale) < 0.001) return;",
    "  currentScale = scale;",
    "  if (document.body) document.body.style.zoom = scale < 0.999 ? String(scale) : \"\";",
    "};",
    "const numberFromStyle = (style, property) => {",
    "  const value = Number.parseFloat(style.getPropertyValue(property));",
    "  return Number.isFinite(value) ? value : 0;",
    "};",
    "const getExpandedDetailsHeight = () => {",
    "  const scrollY = window.scrollY || window.pageYOffset || 0;",
    "  let minTop = 0;",
    "  let maxBottom = 0;",
    '  document.querySelectorAll("details[open]").forEach((element) => {',
    "    const rect = element.getBoundingClientRect();",
    "    if (!Number.isFinite(rect.top) || !Number.isFinite(rect.bottom)) return;",
    "    const top = rect.top + scrollY;",
    "    const expandedHeight = Math.max(rect.height || 0, element.scrollHeight || 0, element.offsetHeight || 0);",
    "    minTop = Math.min(minTop, top);",
    "    maxBottom = Math.max(maxBottom, top + expandedHeight, rect.bottom + scrollY);",
    "  });",
    "  return Math.max(0, maxBottom - Math.min(0, minTop));",
    "};",
    "const getNaturalBounds = () => {",
    "  const root = document.documentElement;",
    "  const body = document.body;",
    "  const scrollX = window.scrollX || window.pageXOffset || 0;",
    "  const scrollY = window.scrollY || window.pageYOffset || 0;",
    "  const viewportHeight = window.innerHeight || root?.clientHeight || 0;",
    "  let minLeft = 0;",
    "  let minTop = 0;",
    "  let maxRight = 0;",
    "  let maxBottom = 0;",
    "  let hasIntrinsicElement = false;",
    "  if (heavyContent) {",
    "    const bodyRect = body?.getBoundingClientRect();",
    "    const contentWidth = Math.max(root?.scrollWidth || 0, body?.scrollWidth || 0, bodyRect?.width || 0);",
    "    const contentHeight = Math.max(root?.scrollHeight || 0, body?.scrollHeight || 0, body?.offsetHeight || 0, bodyRect?.height || 0);",
    "    hasIntrinsicElement = Boolean(document.querySelector(\"canvas,img,video,svg\"));",
    "    return { width: contentWidth, height: contentHeight, hasIntrinsicElement };",
    "  }",
    "  document.querySelectorAll(\"body *\").forEach((element) => {",
    "    const rect = element.getBoundingClientRect();",
    "    if (!Number.isFinite(rect.right) || !Number.isFinite(rect.bottom)) return;",
    "    if (rect.width === 0 && rect.height === 0) return;",
    "    const left = rect.left + scrollX;",
    "    const top = rect.top + scrollY;",
    "    let visualWidth = rect.width;",
    "    let visualHeight = rect.height;",
    "    const canvasWidth = element instanceof HTMLCanvasElement ? element.width : 0;",
    "    const canvasHeight = element instanceof HTMLCanvasElement ? element.height : 0;",
    "    const imageWidth = element instanceof HTMLImageElement ? element.naturalWidth : 0;",
    "    const imageHeight = element instanceof HTMLImageElement ? element.naturalHeight : 0;",
    "    const videoWidth = element instanceof HTMLVideoElement ? element.videoWidth : 0;",
    "    const videoHeight = element instanceof HTMLVideoElement ? element.videoHeight : 0;",
    "    const intrinsicWidth = canvasWidth || imageWidth || videoWidth;",
    "    const intrinsicHeight = canvasHeight || imageHeight || videoHeight;",
    "    if (intrinsicWidth > 0 && intrinsicHeight > 0) {",
    "      hasIntrinsicElement = true;",
    "      const aspectHeight = rect.width > 0 ? rect.width * intrinsicHeight / intrinsicWidth : 0;",
    "      const tracksViewportHeight = Math.abs(rect.height - viewportHeight) <= 2;",
    "      if (aspectHeight > 0) {",
    "        visualHeight = tracksViewportHeight ? aspectHeight : Math.max(visualHeight, aspectHeight);",
    "      }",
    "      if (rect.height > 0 && !tracksViewportHeight) {",
    "        visualWidth = Math.max(visualWidth, rect.height * intrinsicWidth / intrinsicHeight);",
    "      }",
    "    }",
    "    if (element instanceof SVGSVGElement && element.viewBox?.baseVal?.width > 0 && element.viewBox.baseVal.height > 0) {",
    "      hasIntrinsicElement = true;",
    "      const viewBox = element.viewBox.baseVal;",
    "      const aspectHeight = rect.width > 0 ? rect.width * viewBox.height / viewBox.width : 0;",
    "      const tracksViewportHeight = Math.abs(rect.height - viewportHeight) <= 2;",
    "      if (aspectHeight > 0) {",
    "        visualHeight = tracksViewportHeight ? aspectHeight : Math.max(visualHeight, aspectHeight);",
    "      }",
    "      if (rect.height > 0 && !tracksViewportHeight) {",
    "        visualWidth = Math.max(visualWidth, rect.height * viewBox.width / viewBox.height);",
    "      }",
    "    }",
    "    const right = left + visualWidth;",
    "    const bottom = top + visualHeight;",
    "    minLeft = Math.min(minLeft, left);",
    "    minTop = Math.min(minTop, top);",
    "    maxRight = Math.max(maxRight, right);",
    "    maxBottom = Math.max(maxBottom, bottom);",
    "  });",
    "  const contentWidth = Math.max(",
    "    root?.scrollWidth || 0,",
    "    body?.scrollWidth || 0,",
    "    maxRight - Math.min(0, minLeft),",
    "    maxRight,",
    "  );",
    "  const contentHeight = maxBottom - Math.min(0, minTop);",
    "  return { width: contentWidth, height: contentHeight, hasIntrinsicElement };",
    "};",
    "const measure = () => {",
    "  const body = document.body;",
    "  if (!body) return { height: defaultHeight, hasIntrinsicElement: false };",
    "  const bodyStyle = window.getComputedStyle(body);",
    "  const horizontalMargin =",
    '    numberFromStyle(bodyStyle, "margin-left") + numberFromStyle(bodyStyle, "margin-right");',
    "  const verticalMargin =",
    '    numberFromStyle(bodyStyle, "margin-top") + numberFromStyle(bodyStyle, "margin-bottom");',
    "  const reportedViewportWidth = Number(window.__rengeParentViewportWidth);",
    "  const viewportWidth = Math.max(1, Number.isFinite(reportedViewportWidth) && reportedViewportWidth > 0 ? reportedViewportWidth : (window.innerWidth || document.documentElement.clientWidth || defaultHeight));",
    "  const viewportHeight = window.innerHeight || defaultHeight;",
    "  const availableWidth = Math.max(1, viewportWidth - horizontalMargin);",
    "  if (Math.abs(viewportWidth - lastViewportWidth) > 1) naturalLayoutDirty = true;",
    "  lastViewportWidth = viewportWidth;",
    "  if (!naturalLayout || naturalLayoutDirty) {",
    "    setScale(1);",
    "    naturalLayout = {",
    "      bounds: getNaturalBounds(),",
    "      structuralHeight: Math.max(body.scrollHeight || 0, body.offsetHeight || 0, body.getBoundingClientRect().height || 0),",
    "      expandedDetailsHeight: getExpandedDetailsHeight(),",
    "    };",
    "    naturalLayoutDirty = false;",
    "  }",
    "  const bounds = naturalLayout.bounds;",
    "  const structuralHeight = naturalLayout.structuralHeight;",
    "  const expandedDetailsHeight = naturalLayout.expandedDetailsHeight;",
    "  const nextScale = bounds.width > availableWidth ? Math.max(0.1, availableWidth / bounds.width) : 1;",
    "  setScale(nextScale);",
    "  const structuralTracksViewport = Math.abs(structuralHeight - viewportHeight) <= 2;",
    "  if (expandedDetailsHeight > 0 || (structuralHeight > 0 && !structuralTracksViewport)) {",
    "    const measuredStructuralHeight = Math.max(",
    "      expandedDetailsHeight,",
    "      structuralTracksViewport ? 0 : structuralHeight,",
    "    );",
    "    return {",
    "      height: clampHeight((measuredStructuralHeight + verticalMargin) * nextScale + padding),",
    "      hasIntrinsicElement: bounds.hasIntrinsicElement,",
    "    };",
    "  }",
    "  const contentHeight = Math.max(0, bounds.height);",
    "  const contentDelta = contentHeight - lastMeasuredContentHeight;",
    "  const viewportDelta = viewportHeight - lastMeasuredViewportHeight;",
    "  const tracksRecentViewport =",
    "    lastMeasuredContentHeight > 0 &&",
    "    Math.abs(contentDelta - viewportDelta) <= 2 &&",
    "    contentHeight >= viewportHeight - 2 &&",
    "    contentHeight <= viewportHeight + 64;",
    "  lastMeasuredContentHeight = contentHeight;",
    "  lastMeasuredViewportHeight = viewportHeight;",
    "  const tracksViewport = Math.abs(contentHeight - viewportHeight) <= 2;",
    "  const usesProvisionalViewport = viewportHeight <= defaultHeight + 64;",
    "  if (!contentHeight || (!bounds.hasIntrinsicElement && usesProvisionalViewport && (tracksViewport || tracksRecentViewport))) {",
    "    return { height: clampHeight(defaultHeight), hasIntrinsicElement: bounds.hasIntrinsicElement };",
    "  }",
    "  return {",
    "    height: clampHeight(contentHeight * nextScale + verticalMargin + padding),",
    "    hasIntrinsicElement: bounds.hasIntrinsicElement,",
    "  };",
    "};",
    "const postHeight = () => {",
    "  if (rafFallbackTimer) window.clearTimeout(rafFallbackTimer);",
    "  rafFallbackTimer = 0;",
    "  rafId = 0;",
    "  const measurement = measure();",
    "  let height = measurement.height;",
    "  if (lastHeight > 0 && Math.abs(height - lastHeight) <= padding) height = lastHeight;",
    '  const hasExpandedDetails = Boolean(document.querySelector("details[open]"));',
    "  const expandedDetailsHeight = getExpandedDetailsHeight();",
    "  const reportedExpandedHeight = expandedDetailsHeight > 0 ? clampHeight(expandedDetailsHeight * currentScale + padding) : 0;",
    "  const shouldForcePost = forceNextPost;",
    "  forceNextPost = false;",
    "  if (!shouldForcePost && Math.abs(height - lastHeight) < 1 && Math.abs(reportedExpandedHeight - lastExpandedDetailsHeight) < 1 && hasExpandedDetails === lastExpandedDetailsState) return;",
    "  lastHeight = height;",
    "  lastExpandedDetailsHeight = reportedExpandedHeight;",
    "  lastExpandedDetailsState = hasExpandedDetails;",
    "  try {",
    '    parent.postMessage({ type: messageType, id: previewId, height, intrinsic: measurement.hasIntrinsicElement === true, expanded: hasExpandedDetails, expandedHeight: reportedExpandedHeight }, "*");',
    "  } catch {}",
    "};",
    "const requestPostFrame = () => {",
    "  if (rafId || rafFallbackTimer) return;",
    "  rafId = requestAnimationFrame(postHeight);",
    "  rafFallbackTimer = window.setTimeout(() => {",
    "    rafFallbackTimer = 0;",
    "    if (!rafId) return;",
    "    cancelAnimationFrame(rafId);",
    "    rafId = 0;",
    "    postHeight();",
    "  }, 120);",
    "};",
    "const schedulePost = () => {",
    "  if (!heavyContent) {",
    "    requestPostFrame();",
    "    return;",
    "  }",
    "  if (heavyPostTimer) return;",
    "  heavyPostTimer = window.setTimeout(() => {",
    "    heavyPostTimer = 0;",
    "    requestPostFrame();",
    "  }, 160);",
    "};",
    "const observedLayoutAssets = new WeakSet();",
    "const invalidateLayout = () => { naturalLayoutDirty = true; schedulePost(); };",
    "/* Parent remeasure requests are readiness handshakes, so report even when geometry is unchanged. */",
    "const requestMeasurementReport = () => { forceNextPost = true; invalidateLayout(); };",
    "const watchLayoutAssets = () => {",
    '  document.querySelectorAll("img,video,audio").forEach((asset) => {',
    "    if (observedLayoutAssets.has(asset)) return;",
    "    observedLayoutAssets.add(asset);",
    '    ["load", "error", "loadedmetadata"].forEach((eventName) => {',
    "      asset.addEventListener(eventName, invalidateLayout, { once: true });",
    "    });",
    "    if ((asset instanceof HTMLImageElement && asset.complete) ||",
    "        (asset instanceof HTMLMediaElement && asset.readyState >= 1)) {",
    "      queueMicrotask(invalidateLayout);",
    "    }",
    "  });",
    "};",
    'window.addEventListener("message", (event) => {',
    "  const payload = event.data;",
    "  if (!payload || payload.type !== remeasureMessageType || payload.id !== previewId) return;",
    "  watchLayoutAssets();",
    "  requestMeasurementReport();",
    "});",
    'window.addEventListener("load", () => { watchLayoutAssets(); requestMeasurementReport(); });',
    'window.addEventListener("resize", schedulePost);',
    'window.addEventListener("orientationchange", schedulePost);',
    'window.addEventListener("renge-html-preview-viewport-updated", requestMeasurementReport);',
    "try {",
    "  const resizeObserver = new ResizeObserver(schedulePost);",
    "  resizeObserver.observe(document.documentElement);",
    "  if (document.body) resizeObserver.observe(document.body);",
    "  document.addEventListener(\"DOMContentLoaded\", () => {",
    "    if (document.body) resizeObserver.observe(document.body);",
    "    schedulePost();",
    "  }, { once: true });",
    "  window.addEventListener(\"unload\", () => resizeObserver.disconnect(), { once: true });",
    "} catch {}",
    "try {",
    "  const mutationObserver = new MutationObserver((mutations) => {",
    "    const hasMeaningfulMutation = mutations.some((mutation) => !(mutation.type === \"attributes\" && mutation.attributeName === \"style\" && mutation.target === document.body));",
    "    if (hasMeaningfulMutation) {",
    "      watchLayoutAssets();",
    "      naturalLayoutDirty = true;",
    "    }",
    "    schedulePost();",
    "  });",
    "  mutationObserver.observe(document.documentElement, heavyContent",
    "    ? { childList: true, subtree: true }",
    "    : { attributes: true, childList: true, subtree: true, characterData: true });",
    "  window.addEventListener(\"unload\", () => {",
    "    mutationObserver.disconnect();",
    "    if (rafId) cancelAnimationFrame(rafId);",
    "    if (rafFallbackTimer) window.clearTimeout(rafFallbackTimer);",
    "    if (heavyPostTimer) window.clearTimeout(heavyPostTimer);",
    "  }, { once: true });",
    "} catch {}",
    'document.addEventListener("toggle", () => { naturalLayoutDirty = true; schedulePost(); }, true);',
    'document.addEventListener("DOMContentLoaded", () => { watchLayoutAssets(); invalidateLayout(); }, { once: true });',
    "try {",
    "  document.fonts?.ready.then(invalidateLayout, () => undefined);",
    '  document.fonts?.addEventListener("loadingdone", invalidateLayout);',
    '  document.fonts?.addEventListener("loadingerror", invalidateLayout);',
    "} catch {}",
    "watchLayoutAssets();",
    "schedulePost();",
    "(heavyContent ? [240, 1000, 3000, 6000, 12000, 24000] : [80, 240, 600, 1200, 2400, 4000, 8000, 12000, 20000, 30000]).forEach((delay) => setTimeout(() => { naturalLayoutDirty = true; schedulePost(); }, delay));",
    "if (!heavyContent) {",
    "  const intervalId = setInterval(() => { naturalLayoutDirty = true; schedulePost(); }, 750);",
    "  setTimeout(() => clearInterval(intervalId), 30000);",
    "}",
    "})();",
    "</script>",
  ].join("");
}

function injectHtmlPreviewHead(documentContent: string, headInjection: string) {
  const normalizedContent = documentContent.replace(
    /<meta\b(?=[^>]*\bname\s*=\s*["']?viewport\b)[^>]*>/gi,
    "",
  );
  if (/<head[\s>]/i.test(normalizedContent)) {
    return normalizedContent.replace(/<head([^>]*)>/i, `<head$1>${headInjection}`);
  }
  if (/<html[\s>]/i.test(normalizedContent)) {
    return normalizedContent.replace(
      /<html([^>]*)>/i,
      `<html$1><head>${headInjection}</head>`,
    );
  }
  return `<head>${headInjection}</head>${normalizedContent}`;
}

function getIsolatedHtmlPreviewFrame(previewId: string) {
  if (typeof window === "undefined") return null;
  const { protocol, hostname, port } = window.location;
  if (protocol !== "http:" && protocol !== "https:") return null;

  const isLoopbackHost =
    hostname === "127.0.0.1" ||
    hostname === "0.0.0.0" ||
    hostname === "localhost" ||
    hostname === "[::1]" ||
    hostname === "::1" ||
    hostname.endsWith(".localhost");
  if (!isLoopbackHost) return null;

  // A dedicated loopback hostname gives cards a real storage origin for
  // IndexedDB while the browser still keeps them cross-origin from React.
  const origin = `${protocol}//preview.localhost${port ? `:${port}` : ""}`;
  const url = new URL("/html-preview-frame.html", origin);
  url.hash = encodeURIComponent(previewId);
  return { origin, url: url.toString() };
}

function stabilizeHtmlPreviewViewportUnits(content: string) {
  const convertViewportUnits = (value: string) =>
    value.replace(
      /(\d+(?:\.\d+)?)(?:dvh|svh|lvh|vh)\b/gi,
      (match, rawValue: string) => {
        const percentage = Number(rawValue);
        if (!Number.isFinite(percentage)) return match;
        if (percentage === 100) return "var(--TH-viewport-height)";
        return `calc(var(--TH-viewport-height) * ${percentage / 100})`;
      },
    );

  let stabilized = content.replace(
    /(min-height\s*:\s*)([^;{}]*?\d+(?:\.\d+)?(?:dvh|svh|lvh|vh))(?=\s*[;}])/gi,
    (_match, prefix: string, value: string) => `${prefix}${convertViewportUnits(value)}`,
  );
  stabilized = stabilized.replace(
    /(\.style\.minHeight\s*=\s*(["']))([\s\S]*?)(\2)/gi,
    (match, prefix: string, _quote: string, value: string, suffix: string) =>
      /\d+(?:\.\d+)?(?:dvh|svh|lvh|vh)\b/i.test(value)
        ? `${prefix}${convertViewportUnits(value)}${suffix}`
        : match,
  );
  stabilized = stabilized.replace(
    /(setProperty\s*\(\s*(["'])min-height\2\s*,\s*(["']))([\s\S]*?)(\3\s*\))/gi,
    (match, prefix: string, _firstQuote: string, _secondQuote: string, value: string, suffix: string) =>
      /\d+(?:\.\d+)?(?:dvh|svh|lvh|vh)\b/i.test(value)
        ? `${prefix}${convertViewportUnits(value)}${suffix}`
        : match,
  );
  return stabilized;
}

function isolateHtmlPreviewParentReferences(content: string) {
  // SillyTavern character frontends commonly read APIs from `parent`/`top`.
  // Renge installs the same compatibility APIs inside the preview itself, so
  // keep those calls working locally while preventing card code from reaching
  // or rewriting the React host document. `postMessage` remains pointed at the
  // real parent because it is the only supported cross-frame transport.
  return content
    .replace(
      /(?<![\w$.])(?:window\s*\.\s*)?(?:parent|top)\s*(?:\?\.|\.)\s*(?!postMessage\b)([A-Za-z_$][\w$]*)/g,
      "window.$1",
    )
    .replace(
      /(?<![\w$.])(?:window\s*\.\s*)?(?:parent|top)\s*(?:\?\.)?\s*\[\s*(["'])(?!postMessage\1)([^"']+)\1\s*\]/g,
      "window[$1$2$1]",
    );
}

function buildHtmlPreviewEmbeddedFramesScript(previewId: string) {
  const previewIdLiteral = serializeHtmlPreviewValue(previewId);
  const resizeMessageTypeLiteral = serializeHtmlPreviewValue(
    HTML_PREVIEW_RESIZE_MESSAGE,
  );
  const remeasureMessageTypeLiteral = serializeHtmlPreviewValue(
    HTML_PREVIEW_REMEASURE_MESSAGE,
  );

  return [
    '<script data-renge-html-preview-embedded-frames="true">',
    "(() => {",
    `const previewId = ${previewIdLiteral};`,
    `const resizeMessageType = ${resizeMessageTypeLiteral};`,
    `const remeasureMessageType = ${remeasureMessageTypeLiteral};`,
    'const frameSelector = "iframe[data-renge-embedded-html-frame=\\"true\\"]";',
    "const getFrames = () => Array.from(document.querySelectorAll(frameSelector));",
    "const getSourceFrame = (source) => getFrames().find((frame) => frame.contentWindow === source);",
    "const resizeFrame = (frame, height) => {",
    "  const parsed = Number(height);",
    "  if (!Number.isFinite(parsed) || parsed <= 0) return;",
    `  const nextHeight = Math.max(${HTML_PREVIEW_MEASURED_MIN_HEIGHT}, Math.min(${HTML_PREVIEW_MAX_HEIGHT}, Math.ceil(parsed)));`,
    '  frame.style.height = `${nextHeight}px`;',
    '  frame.dataset.rengeMeasuredHeight = String(nextHeight);',
    "};",
    'window.addEventListener("message", (event) => {',
    "  const payload = event.data;",
    '  if (!payload || typeof payload !== "object" || payload.id !== previewId) return;',
    "  const sourceFrame = getSourceFrame(event.source);",
    "  if (sourceFrame) {",
    "    if (payload.type === resizeMessageType) { resizeFrame(sourceFrame, payload.height); return; }",
    '    try { parent.postMessage(payload, "*"); } catch {}',
    "    return;",
    "  }",
    "  if (event.source !== parent) return;",
    "  getFrames().forEach((frame) => {",
    '    try { frame.contentWindow?.postMessage(payload, "*"); } catch {}',
    "  });",
    "}, true);",
    "const requestFrameMeasurements = () => getFrames().forEach((frame) => {",
    '  try { frame.contentWindow?.postMessage({ type: remeasureMessageType, id: previewId }, "*"); } catch {}',
    "});",
    'if (document.readyState === "loading") document.addEventListener("DOMContentLoaded", requestFrameMeasurements, { once: true });',
    "else queueMicrotask(requestFrameMeasurements);",
    "})();",
    "</script>",
  ].join("");
}

function expandEmbeddedHtmlPreviewDocuments(
  content: string,
  previewId: string,
  context: HtmlPreviewContext,
  embeddedDepth: number,
): string {
  if (embeddedDepth >= 4) return content;
  let embeddedIndex = 0;
  return content.replace(
    /<script\s+type=["']application\/x-renge-embedded-html["']\s*>([A-Za-z0-9+/=\s]+)<\/script>/gi,
    (_match, encodedContent: string) => {
      try {
        const embeddedContent = decodeEmbeddedHtmlDocument(encodedContent);
        const embeddedDocument: string = buildHtmlPreviewDocument(
          embeddedContent,
          previewId,
          context,
          embeddedDepth + 1,
        );
        const frameIndex = embeddedIndex;
        embeddedIndex += 1;
        return `<iframe allow="autoplay; fullscreen; gamepad" data-renge-embedded-html-frame="true" data-renge-embedded-index="${frameIndex}" loading="eager" sandbox="allow-downloads allow-forms allow-modals allow-popups allow-popups-to-escape-sandbox allow-presentation allow-same-origin allow-scripts" srcdoc="${escapeChatHtmlAttribute(embeddedDocument)}" title="嵌套 HTML 预览"></iframe>`;
      } catch {
        return "";
      }
    },
  );
}

function buildHtmlPreviewDocument(
  content: string,
  previewId: string,
  context: HtmlPreviewContext,
  embeddedDepth = 0,
): string {
  const isolatedContent = isolateHtmlPreviewParentReferences(
    stabilizeHtmlPreviewViewportUnits(content.trim()),
  );
  const trimmedContent: string = expandEmbeddedHtmlPreviewDocuments(
    isolatedContent,
    previewId,
    context,
    embeddedDepth,
  );
  const heavyContent = trimmedContent.length >= HTML_PREVIEW_HEAVY_CONTENT_THRESHOLD;
  // SillyTavern frontends can replace the complete body through
  // `$("body").load(...)`. Install the resize runtime in the head before card
  // scripts start, so asynchronous body replacement cannot remove the only
  // path that reports the finished layout height to the host.
  const embeddedFramesScript = trimmedContent.includes(
    'data-renge-embedded-html-frame="true"',
  )
    ? buildHtmlPreviewEmbeddedFramesScript(previewId)
    : "";
  const headInjection = `${htmlPreviewViewportMeta}${htmlPreviewStyle}${htmlPreviewJqueryScript}${htmlPreviewBootstrapScript}${htmlPreviewJqueryDelegationScript}${buildHtmlPreviewVariablesScript(previewId, context)}${buildHtmlPreviewPersonalizationScript(context)}${embeddedFramesScript}${buildHtmlPreviewScript(previewId, heavyContent)}`;
  if (/<!doctype\s+html|<html[\s>]/i.test(trimmedContent)) {
    return injectHtmlPreviewHead(trimmedContent, headInjection);
  }
  if (/<head[\s>]|<body[\s>]/i.test(trimmedContent)) {
    return `<!doctype html><html lang="zh-CN">${injectHtmlPreviewHead(trimmedContent, headInjection)}</html>`;
  }

  return [
    "<!doctype html>",
    '<html lang="zh-CN">',
    "<head>",
    '<meta charset="utf-8" />',
    "<style>html,body{min-height:100%;}body{margin:0;}</style>",
    headInjection,
    "</head>",
    "<body>",
    trimmedContent,
    "</body>",
    "</html>",
  ].join("");
}

type ChatHtmlPreviewProps = {
  content: string;
  context: HtmlPreviewContext;
  mountReady: boolean;
  messageId: string;
  previewId: string;
  frameRegistry: { current: Map<string, HTMLIFrameElement> };
};

function ChatHtmlPreview({
  content,
  context,
  mountReady,
  messageId,
  previewId,
  frameRegistry,
}: ChatHtmlPreviewProps) {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const frameRef = useRef<HTMLIFrameElement | null>(null);
  const requestHeavyMountRef = useRef<() => void>(() => {});
  const initializedFrameRef = useRef<HTMLIFrameElement | null>(null);
  const heavyContent = content.trim().length >= HTML_PREVIEW_HEAVY_CONTENT_THRESHOLD;
  const containsExpandedDetails =
    /<details\b(?=[^>]*\bopen(?:\s|=|>))[^>]*>/i.test(content);
  const [renderReady, setRenderReady] = useState(false);
  const sourceDocumentRef = useRef<{
    content: string;
    previewId: string;
    value: string;
  } | null>(null);
  const isolatedFrame = useMemo(
    () => getIsolatedHtmlPreviewFrame(previewId),
    [previewId],
  );

  if (
    mountReady &&
    renderReady &&
    (!sourceDocumentRef.current ||
      sourceDocumentRef.current.content !== content ||
      sourceDocumentRef.current.previewId !== previewId)
  ) {
    sourceDocumentRef.current = {
      content,
      previewId,
      value: buildHtmlPreviewDocument(content, previewId, context),
    };
  }

  useEffect(() => {
    if (!mountReady) {
      setRenderReady(false);
      sourceDocumentRef.current = null;
      requestHeavyMountRef.current = () => {};
      return;
    }

    if (!heavyContent) {
      let firstFrame = 0;
      let secondFrame = 0;
      firstFrame = window.requestAnimationFrame(() => {
        secondFrame = window.requestAnimationFrame(() => setRenderReady(true));
      });
      return () => {
        window.cancelAnimationFrame(firstFrame);
        window.cancelAnimationFrame(secondFrame);
      };
    }

    const container = containerRef.current;
    if (!container) return;
    const unsubscribeHeavyPreview = subscribeHeavyHtmlPreview(
      previewId,
      setRenderReady,
    );
    let cancelQueuedMount: (() => void) | null = null;
    let visibilityTimer = 0;
    let queued = false;
    const queueMount = () => {
      if (queued) return;
      queued = true;
      cancelQueuedMount = enqueueHeavyHtmlPreviewMount(() => {
        queued = false;
        cancelQueuedMount = null;
        activateHeavyHtmlPreview(previewId);
      });
    };
    requestHeavyMountRef.current = queueMount;

    if (typeof IntersectionObserver !== "function") {
      const fallbackTimer = window.setTimeout(
        queueMount,
        HTML_PREVIEW_HEAVY_AUTO_LOAD_DELAY,
      );
      return () => {
        window.clearTimeout(fallbackTimer);
        requestHeavyMountRef.current = () => {};
        cancelQueuedMount?.();
        unsubscribeHeavyPreview();
      };
    }

    let observer: IntersectionObserver | null = null;
    const observerStartTimer = window.setTimeout(() => {
      observer = new IntersectionObserver(
        (entries) => {
          const steadilyVisible = entries.some(
            (entry) => entry.isIntersecting && entry.intersectionRatio >= 0.6,
          );
          if (!steadilyVisible) {
            if (visibilityTimer) window.clearTimeout(visibilityTimer);
            visibilityTimer = 0;
            return;
          }
          if (visibilityTimer) return;
          visibilityTimer = window.setTimeout(() => {
            visibilityTimer = 0;
            observer?.disconnect();
            queueMount();
          }, 300);
        },
        { threshold: [0.6] },
      );
      observer.observe(container);
    }, HTML_PREVIEW_HEAVY_AUTO_LOAD_DELAY);

    return () => {
      window.clearTimeout(observerStartTimer);
      observer?.disconnect();
      if (visibilityTimer) window.clearTimeout(visibilityTimer);
      requestHeavyMountRef.current = () => {};
      cancelQueuedMount?.();
      unsubscribeHeavyPreview();
    };
  }, [heavyContent, mountReady, previewId]);

  const sendContextUpdate = useCallback(() => {
    const frameWindow = frameRef.current?.contentWindow;
    if (!frameWindow) return;
    frameWindow.postMessage(
      {
        type: HTML_PREVIEW_CONTEXT_UPDATE_MESSAGE,
        id: previewId,
        context,
      },
      "*",
    );
  }, [context, previewId]);

  const sendViewportUpdate = useCallback(() => {
    const frame = frameRef.current;
    const frameWidth = frame?.getBoundingClientRect().width || frame?.clientWidth || 0;
    const container = containerRef.current;
    const containerWidth =
      container?.getBoundingClientRect().width || container?.clientWidth || 0;
    frameRef.current?.contentWindow?.postMessage(
      {
        type: HTML_PREVIEW_VIEWPORT_MESSAGE,
        id: previewId,
        width:
          frameWidth ||
          containerWidth ||
          window.visualViewport?.width ||
          window.innerWidth,
        height: window.visualViewport?.height ?? window.innerHeight,
      },
      "*",
    );
  }, [previewId]);

  const requestLayoutMeasurement = useCallback(() => {
    frameRef.current?.contentWindow?.postMessage(
      {
        type: HTML_PREVIEW_REMEASURE_MESSAGE,
        id: previewId,
      },
      "*",
    );
  }, [previewId]);

  useEffect(() => {
    sendContextUpdate();
    requestLayoutMeasurement();
  }, [requestLayoutMeasurement, sendContextUpdate]);

  useEffect(() => {
    const update = () => sendViewportUpdate();
    window.addEventListener("resize", update);
    window.addEventListener("orientationchange", update);
    window.visualViewport?.addEventListener("resize", update);
    const container = containerRef.current;
    let lastObservedWidth = container?.getBoundingClientRect().width ?? 0;
    const resizeObserver =
      container && typeof ResizeObserver === "function"
        ? new ResizeObserver((entries) => {
            const nextWidth = entries[0]?.contentRect.width ?? 0;
            if (Math.abs(nextWidth - lastObservedWidth) <= 1) return;
            lastObservedWidth = nextWidth;
            sendViewportUpdate();
            requestLayoutMeasurement();
          })
        : null;
    if (container) resizeObserver?.observe(container);
    return () => {
      window.removeEventListener("resize", update);
      window.removeEventListener("orientationchange", update);
      window.visualViewport?.removeEventListener("resize", update);
      resizeObserver?.disconnect();
    };
  }, [requestLayoutMeasurement, sendViewportUpdate]);

  const registerFrame = useCallback(
    (frame: HTMLIFrameElement | null) => {
      const previousFrame = frameRef.current;
      if (
        previousFrame &&
        previousFrame !== frame &&
        frameRegistry.current.get(previewId) === previousFrame
      ) {
        frameRegistry.current.delete(previewId);
      }
      frameRef.current = frame;
      if (frame) frameRegistry.current.set(previewId, frame);
      else if (frameRegistry.current.get(previewId) === previousFrame) {
        frameRegistry.current.delete(previewId);
      }
    },
    [frameRegistry, previewId],
  );

  const handleLoad = useCallback(
    (event: SyntheticEvent<HTMLIFrameElement>) => {
      resizeHtmlPreviewFrame(event);
      const loadedFrame = event.currentTarget;
      if (
        isolatedFrame &&
        initializedFrameRef.current !== loadedFrame &&
        sourceDocumentRef.current
      ) {
        initializedFrameRef.current = loadedFrame;
        loadedFrame.contentWindow?.postMessage(
          {
            type: HTML_PREVIEW_FRAME_INIT_MESSAGE,
            id: previewId,
            document: sourceDocumentRef.current.value,
          },
          isolatedFrame.origin,
        );
      }
      const synchronizeLoadedFrame = () => {
        if (frameRef.current !== loadedFrame) return;
        sendContextUpdate();
        sendViewportUpdate();
        requestLayoutMeasurement();
      };
      window.requestAnimationFrame(() => {
        synchronizeLoadedFrame();
      });
      [80, 240, 600, 1200, 2400].forEach((delay) => {
        window.setTimeout(synchronizeLoadedFrame, delay);
      });
    },
    [
      isolatedFrame,
      previewId,
      requestLayoutMeasurement,
      sendContextUpdate,
      sendViewportUpdate,
    ],
  );

  return (
    <div
      className={`chat-html-preview ${heavyContent ? "heavy" : ""} ${
        mountReady && renderReady ? "" : "pending"
      }`}
      data-preview-id={previewId}
      ref={containerRef}
    >
      {mountReady && renderReady && sourceDocumentRef.current ? (
        <iframe
          className="chat-html-frame"
          allow="autoplay; fullscreen; gamepad"
          allowFullScreen
          data-expanded-layout={containsExpandedDetails ? "true" : "false"}
          data-message-id={messageId}
          loading="eager"
          onLoad={handleLoad}
          ref={registerFrame}
          referrerPolicy="no-referrer"
          sandbox={
            isolatedFrame
              ? "allow-downloads allow-forms allow-modals allow-popups allow-popups-to-escape-sandbox allow-presentation allow-same-origin allow-scripts"
              : "allow-downloads allow-forms allow-modals allow-popups allow-popups-to-escape-sandbox allow-presentation allow-scripts"
          }
          src={isolatedFrame?.url}
          srcDoc={isolatedFrame ? undefined : sourceDocumentRef.current.value}
          style={
            containsExpandedDetails
              ? { minHeight: `${HTML_PREVIEW_EXPANDED_MIN_HEIGHT}px` }
              : undefined
          }
          tabIndex={0}
          title="HTML 预览"
        />
      ) : (
        <div className="chat-html-preview-placeholder" role="status">
          <span>
            {!mountReady
              ? "正在同步角色卡会话与脚本环境…"
              : heavyContent
                ? "大型 HTML 已排队加载；最多同时保留 3 个运行实例。"
                : "正在安全挂载角色卡 HTML…"}
          </span>
          {mountReady && heavyContent && (
            <button type="button" onClick={() => requestHeavyMountRef.current()}>
              立即加载
            </button>
          )}
        </div>
      )}
    </div>
  );
}

function measureHtmlPreviewHeight(frame: HTMLIFrameElement) {
  const doc = frame.contentDocument;
  if (!doc) return 0;

  const root = doc.documentElement;
  const body = doc.body;
  const baseHeight = Math.max(
    root.scrollHeight,
    root.offsetHeight,
    root.clientHeight,
    body?.scrollHeight ?? 0,
    body?.offsetHeight ?? 0,
    body?.clientHeight ?? 0,
  );
  const scrollY = frame.contentWindow?.scrollY ?? 0;
  const elementBottom = Array.from(doc.body?.querySelectorAll("*") ?? []).reduce(
    (maxBottom, element) => {
      const rect = element.getBoundingClientRect();
      if (!Number.isFinite(rect.bottom) || (rect.width === 0 && rect.height === 0)) {
        return maxBottom;
      }
      return Math.max(maxBottom, rect.bottom + scrollY);
    },
    0,
  );

  return Math.max(baseHeight, elementBottom);
}

function fitHtmlPreviewFrame(frame: HTMLIFrameElement) {
  try {
    const measuredHeight = measureHtmlPreviewHeight(frame);
    // The sandbox deliberately withholds contentDocument from the host. A
    // missing measurement is not a 0px document: leave the provisional frame
    // height intact until the child resize bridge reports its real layout.
    if (measuredHeight <= 0) return;
    const height = Math.ceil(measuredHeight + 12);
    frame.style.height = `${Math.max(HTML_PREVIEW_MEASURED_MIN_HEIGHT, height)}px`;
  } catch {
    // Preview internals should not break chat rendering.
  }
}

function resizeHtmlPreviewFrame(event: SyntheticEvent<HTMLIFrameElement>) {
  const frame = event.currentTarget;
  const frameWidth = frame.getBoundingClientRect().width || frame.clientWidth || 0;
  if (frameWidth > 0) {
    const expandedLayoutMinHeight =
      frame.dataset.expandedLayout === "true"
        ? Math.max(HTML_PREVIEW_EXPANDED_MIN_HEIGHT, frameWidth * 0.9)
        : 0;
    const measuringHeight = Math.max(
      420,
      expandedLayoutMinHeight,
      Math.min(960, Math.round(frameWidth * 0.72)),
    );
    frame.style.height = `${measuringHeight}px`;
  }
  fitHtmlPreviewFrame(frame);
  [80, 240, 600].forEach((delay) => {
    window.setTimeout(() => fitHtmlPreviewFrame(frame), delay);
  });
}

function renderInlineText(content: string): ReactNode[] {
  const nodes: ReactNode[] = [];
  const normalizedContent = stripHiddenImageAnnotations(content);
  // 个性化引用覆盖半角/全角双引号、中文弯引号、书名式引号和半角角括号。
  const inlinePattern =
    /`(?<code>[^`]+)`|(?<bareImage>https?:\/\/\S+?\.(?:png|jpe?g|webp|gif)(?:\?\S*)?|data:image\/[a-zA-Z+.-]+;base64,[A-Za-z0-9+/=]+)|!\[(?<imageAlt>[^\]]*)\]\s*\(\s*(?<imageUrl>[^)\s]+)\s*\)|\[(?<linkText>[^\]]+)\]\s*\(\s*(?<linkUrl>[^)\s]+)\s*\)|(?<personalizedQuote>"[^"\n]+"|＂[^＂\n]+＂|“[^”\n]+”|〝[^〞\n]+〞|「[^」\n]+」|｢[^｣\n]+｣|『[^』\n]+』)|\*\*(?<doubleAsterisk>[^*]+)\*\*|__(?<doubleUnderscore>[^_]+)__|~~(?<deleted>[^~]+)~~|\*(?<asteriskEm>[^*\n]+)\*|_(?<underscoreEm>[^_\n]+)_/g;
  let cursor = 0;
  let match: RegExpExecArray | null;

  while ((match = inlinePattern.exec(normalizedContent))) {
    if (match.index > cursor) nodes.push(normalizedContent.slice(cursor, match.index));
    const groups = match.groups ?? {};

    if (groups.code !== undefined) {
      nodes.push(<code key={`code-${match.index}`}>{groups.code}</code>);
    } else if (groups.bareImage !== undefined) {
      // 裸图片 URL（http(s) 直链或 data:image/...）
      nodes.push(
        <img
          key={`bare-img-${match.index}`}
          src={groups.bareImage}
          alt="生成的图片"
          className="chat-inline-image"
          loading="lazy"
        />,
      );
    } else if (groups.imageAlt !== undefined && groups.imageUrl !== undefined) {
      nodes.push(
        <img
          key={`img-${match.index}`}
          src={groups.imageUrl}
          alt={groups.imageAlt || "生成的图片"}
          className="chat-inline-image"
          loading="lazy"
        />,
      );
    } else if (groups.linkText !== undefined && groups.linkUrl !== undefined) {
      nodes.push(
        <a
          className="chat-inline-link"
          href={groups.linkUrl}
          key={`link-${match.index}`}
          rel="noreferrer"
          target="_blank"
          title={groups.linkUrl}
        >
          {groups.linkText}
        </a>,
      );
    } else if (groups.personalizedQuote !== undefined) {
      const quote = groups.personalizedQuote;
      nodes.push(
        <span className="chat-personalized-quote" key={`quote-${match.index}`}>
          {quote.slice(0, 1)}
          {renderInlineText(quote.slice(1, -1))}
          {quote.slice(-1)}
        </span>,
      );
    } else if (groups.doubleAsterisk !== undefined) {
      nodes.push(
        <strong key={`strong-${match.index}`}>
          {renderInlineText(groups.doubleAsterisk)}
        </strong>,
      );
    } else if (groups.doubleUnderscore !== undefined) {
      nodes.push(
        <strong key={`strong-${match.index}`}>
          {renderInlineText(groups.doubleUnderscore)}
        </strong>,
      );
    } else if (groups.deleted !== undefined) {
      nodes.push(<del key={`del-${match.index}`}>{groups.deleted}</del>);
    } else if (groups.asteriskEm !== undefined) {
      nodes.push(
        <em className="chat-personalized-italic" key={`em-${match.index}`}>
          {renderInlineText(groups.asteriskEm)}
        </em>,
      );
    } else if (groups.underscoreEm !== undefined) {
      nodes.push(<em key={`em-${match.index}`}>{groups.underscoreEm}</em>);
    }
    cursor = match.index + match[0].length;
  }

  if (cursor < normalizedContent.length) nodes.push(normalizedContent.slice(cursor));
  return nodes;
}

function splitMarkdownTableRow(line: string) {
  return line
    .trim()
    .replace(/^\|/, "")
    .replace(/\|$/, "")
    .split("|")
    .map((cell) => cell.trim());
}

function isMarkdownTableSeparator(line: string) {
  const cells = splitMarkdownTableRow(line);
  return cells.length > 1 && cells.every((cell) => /^:?-{3,}:?$/.test(cell));
}

function renderMarkdownParagraph(lines: string[], key: string) {
  return (
    <p className="chat-text-part" key={key}>
      {renderInlineText(lines.join("\n"))}
    </p>
  );
}

function renderMarkdownList(
  lines: string[],
  ordered: boolean,
  key: string,
) {
  const listItems = lines.map((line) => {
    const match = ordered
      ? /^\s*\d+\.\s+(.*)$/.exec(line)
      : /^\s*[-*+]\s+(\[[ xX]\]\s+)?(.*)$/.exec(line);
    const taskMarker = !ordered ? match?.[1] : undefined;
    const content = ordered ? match?.[1] ?? line : match?.[2] ?? line;
    const checked = taskMarker ? /\[[xX]\]/.test(taskMarker) : null;

    return { content, checked };
  });
  const Tag = ordered ? "ol" : "ul";

  return (
    <Tag className="chat-markdown-list" key={key}>
      {listItems.map((item, index) => (
        <li key={`${key}-item-${index}`}>
          {item.checked !== null && (
            <input checked={item.checked} readOnly tabIndex={-1} type="checkbox" />
          )}
          <span>{renderInlineText(item.content)}</span>
        </li>
      ))}
    </Tag>
  );
}

function renderMarkdownTable(lines: string[], key: string) {
  const headerCells = splitMarkdownTableRow(lines[0]);
  const bodyRows = lines.slice(2).map(splitMarkdownTableRow);

  return (
    <div className="chat-markdown-table-wrap" key={key}>
      <table className="chat-markdown-table">
        <thead>
          <tr>
            {headerCells.map((cell, index) => (
              <th key={`${key}-head-${index}`}>{renderInlineText(cell)}</th>
            ))}
          </tr>
        </thead>
        <tbody>
          {bodyRows.map((row, rowIndex) => (
            <tr key={`${key}-row-${rowIndex}`}>
              {headerCells.map((_, cellIndex) => (
                <td key={`${key}-cell-${rowIndex}-${cellIndex}`}>
                  {renderInlineText(row[cellIndex] ?? "")}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function renderMarkdownHeading(level: number, content: string, key: string) {
  const className = "chat-markdown-heading";
  const children = renderInlineText(content);

  switch (level) {
    case 1:
      return <h1 className={className} key={key}>{children}</h1>;
    case 2:
      return <h2 className={className} key={key}>{children}</h2>;
    case 3:
      return <h3 className={className} key={key}>{children}</h3>;
    case 4:
      return <h4 className={className} key={key}>{children}</h4>;
    case 5:
      return <h5 className={className} key={key}>{children}</h5>;
    default:
      return <h6 className={className} key={key}>{children}</h6>;
  }
}

function renderMarkdownBlocks(content: string, keyPrefix: string) {
  const lines = content.replace(/\r\n/g, "\n").split("\n");
  const nodes: ReactNode[] = [];
  let index = 0;

  while (index < lines.length) {
    const line = lines[index];
    const trimmedLine = line.trim();
    const key = `${keyPrefix}-md-${index}`;

    if (!trimmedLine) {
      index += 1;
      continue;
    }

    const headingMatch = /^(#{1,6})\s+(.+)$/.exec(trimmedLine);
    if (headingMatch) {
      const level = Math.min(6, headingMatch[1].length);
      nodes.push(renderMarkdownHeading(level, headingMatch[2], key));
      index += 1;
      continue;
    }

    if (/^(-{3,}|\*{3,}|_{3,})$/.test(trimmedLine)) {
      nodes.push(<hr className="chat-markdown-hr" key={key} />);
      index += 1;
      continue;
    }

    if (trimmedLine.startsWith(">")) {
      const quoteLines: string[] = [];
      while (index < lines.length && lines[index].trim().startsWith(">")) {
        quoteLines.push(lines[index].trim().replace(/^>\s?/, ""));
        index += 1;
      }
      nodes.push(
        <blockquote className="chat-markdown-quote" key={key}>
          {renderMarkdownBlocks(quoteLines.join("\n"), `${key}-quote`)}
        </blockquote>,
      );
      continue;
    }

    if (
      index + 1 < lines.length &&
      trimmedLine.includes("|") &&
      isMarkdownTableSeparator(lines[index + 1])
    ) {
      const tableLines = [line, lines[index + 1]];
      index += 2;
      while (index < lines.length && lines[index].includes("|") && lines[index].trim()) {
        tableLines.push(lines[index]);
        index += 1;
      }
      nodes.push(renderMarkdownTable(tableLines, key));
      continue;
    }

    if (/^\s*[-*+]\s+/.test(line)) {
      const listLines: string[] = [];
      while (index < lines.length && /^\s*[-*+]\s+/.test(lines[index])) {
        listLines.push(lines[index]);
        index += 1;
      }
      nodes.push(renderMarkdownList(listLines, false, key));
      continue;
    }

    if (/^\s*\d+\.\s+/.test(line)) {
      const listLines: string[] = [];
      while (index < lines.length && /^\s*\d+\.\s+/.test(lines[index])) {
        listLines.push(lines[index]);
        index += 1;
      }
      nodes.push(renderMarkdownList(listLines, true, key));
      continue;
    }

    const paragraphLines = [line];
    index += 1;
    while (
      index < lines.length &&
      lines[index].trim() &&
      !/^(#{1,6})\s+/.test(lines[index].trim()) &&
      !/^(-{3,}|\*{3,}|_{3,})$/.test(lines[index].trim()) &&
      !lines[index].trim().startsWith(">") &&
      !/^\s*[-*+]\s+/.test(lines[index]) &&
      !/^\s*\d+\.\s+/.test(lines[index])
    ) {
      if (
        index + 1 < lines.length &&
        lines[index].includes("|") &&
        isMarkdownTableSeparator(lines[index + 1])
      ) {
        break;
      }
      paragraphLines.push(lines[index]);
      index += 1;
    }
    nodes.push(renderMarkdownParagraph(paragraphLines, key));
  }

  return nodes;
}

function canEditChatMessageAsRendered(content: string, htmlRenderEnabled: boolean) {
  const parts = parseChatContentParts(content, htmlRenderEnabled);
  return parts.every(
    (part) =>
      part.type === "text" &&
      !(htmlRenderEnabled && looksLikeStandaloneRenderableHtml(part.content)),
  );
}

function serializeRenderedEditorInline(node: Node): string {
  if (node.nodeType === Node.TEXT_NODE) return node.textContent ?? "";
  if (!(node instanceof HTMLElement)) return "";

  const tagName = node.tagName.toLowerCase();
  if (tagName === "br") return "\n";
  if (tagName === "img") {
    return `![${node.getAttribute("alt") ?? ""}](${node.getAttribute("src") ?? ""})`;
  }

  const content = Array.from(node.childNodes).map(serializeRenderedEditorInline).join("");
  if (tagName === "strong" || tagName === "b") return `**${content}**`;
  if (tagName === "em" || tagName === "i") return `*${content}*`;
  if (tagName === "del" || tagName === "s") return `~~${content}~~`;
  if (tagName === "code") return `\`${content}\``;
  if (tagName === "a") return `[${content}](${node.getAttribute("href") ?? ""})`;
  if (tagName === "div" || tagName === "p") return `${content}\n`;
  return content;
}

function serializeRenderedEditorBlock(element: HTMLElement): string {
  const tagName = element.tagName.toLowerCase();
  if (/^h[1-6]$/.test(tagName)) {
    return `${"#".repeat(Number(tagName.slice(1)))} ${serializeRenderedEditorInline(element).trim()}`;
  }
  if (tagName === "p") return serializeRenderedEditorInline(element).replace(/\n$/, "");
  if (tagName === "hr") return "---";
  if (tagName === "blockquote") {
    return Array.from(element.children)
      .map((child) => serializeRenderedEditorBlock(child as HTMLElement))
      .join("\n\n")
      .split("\n")
      .map((line) => `> ${line}`)
      .join("\n");
  }
  if (tagName === "ul" || tagName === "ol") {
    return Array.from(element.children)
      .filter((child) => child.tagName.toLowerCase() === "li")
      .map((child, index) => {
        const listItem = child as HTMLElement;
        const checkbox = listItem.querySelector<HTMLInputElement>('input[type="checkbox"]');
        const contentElement = listItem.querySelector<HTMLElement>(":scope > span") ?? listItem;
        const marker = tagName === "ol" ? `${index + 1}.` : "-";
        const taskMarker = checkbox ? ` [${checkbox.checked ? "x" : " "}]` : "";
        return `${marker}${taskMarker} ${serializeRenderedEditorInline(contentElement).trim()}`;
      })
      .join("\n");
  }
  if (element.classList.contains("chat-markdown-table-wrap")) {
    const rows = Array.from(element.querySelectorAll("tr")).map((row) =>
      Array.from(row.querySelectorAll("th, td")).map((cell) =>
        serializeRenderedEditorInline(cell).trim(),
      ),
    );
    if (rows.length === 0) return "";
    const columnCount = Math.max(...rows.map((row) => row.length));
    const normalizedRows = rows.map((row) => [
      ...row,
      ...Array.from({ length: Math.max(0, columnCount - row.length) }, () => ""),
    ]);
    return [
      `| ${normalizedRows[0].join(" | ")} |`,
      `| ${Array.from({ length: columnCount }, () => "---").join(" | ")} |`,
      ...normalizedRows.slice(1).map((row) => `| ${row.join(" | ")} |`),
    ].join("\n");
  }
  return serializeRenderedEditorInline(element).trimEnd();
}

function serializeRenderedChatEditor(editor: HTMLElement) {
  const markdownRoots = Array.from(editor.querySelectorAll<HTMLElement>(":scope .chat-markdown"));
  const roots = markdownRoots.length > 0 ? markdownRoots : [editor];
  return roots
    .flatMap((root) => Array.from(root.children) as HTMLElement[])
    .map(serializeRenderedEditorBlock)
    .filter((content) => content.trim())
    .join("\n\n")
    .replace(/\u00a0/g, " ")
    .trim();
}

function getTextOffsetAtPoint(container: HTMLElement, x: number, y: number) {
  const documentWithCaret = document as Document & {
    caretRangeFromPoint?: (clientX: number, clientY: number) => Range | null;
    caretPositionFromPoint?: (
      clientX: number,
      clientY: number,
    ) => { offsetNode: Node; offset: number } | null;
  };
  const caretRange = documentWithCaret.caretRangeFromPoint?.(x, y) ?? null;
  const caretPosition = caretRange
    ? { node: caretRange.startContainer, offset: caretRange.startOffset }
    : (() => {
        const position = documentWithCaret.caretPositionFromPoint?.(x, y);
        return position ? { node: position.offsetNode, offset: position.offset } : null;
      })();
  if (!caretPosition) return null;
  const caretElement =
    caretPosition.node.nodeType === Node.ELEMENT_NODE
      ? (caretPosition.node as Element)
      : caretPosition.node.parentElement;
  if (!caretElement || !container.contains(caretElement)) return null;

  try {
    const precedingRange = document.createRange();
    precedingRange.selectNodeContents(container);
    precedingRange.setEnd(caretPosition.node, caretPosition.offset);
    return precedingRange.toString().length;
  } catch {
    return null;
  }
}

function placeCaretAtTextOffset(container: HTMLElement, requestedOffset: number | null) {
  const selection = window.getSelection();
  if (!selection) return;
  const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT);
  let remainingOffset = Math.max(0, requestedOffset ?? Number.POSITIVE_INFINITY);
  let lastTextNode: Text | null = null;
  let currentNode = walker.nextNode();

  while (currentNode) {
    const textNode = currentNode as Text;
    lastTextNode = textNode;
    if (remainingOffset <= textNode.data.length) {
      const range = document.createRange();
      range.setStart(textNode, remainingOffset);
      range.collapse(true);
      selection.removeAllRanges();
      selection.addRange(range);
      return;
    }
    remainingOffset -= textNode.data.length;
    currentNode = walker.nextNode();
  }

  const range = document.createRange();
  if (lastTextNode) range.setStart(lastTextNode, lastTextNode.data.length);
  else range.selectNodeContents(container);
  range.collapse(false);
  selection.removeAllRanges();
  selection.addRange(range);
}

function ChatLiveStreamPanel({ stream }: { stream: ChatLiveStreamEmbed }) {
  const renderLaneItems = (
    items: ChatLiveStreamTextItem[],
    keyPrefix: string,
    hidden = false,
  ) => (
    <div
      className="chat-live-stream-marquee-group"
      aria-hidden={hidden ? "true" : undefined}
    >
      {items.map((item, index) => (
        <span
          key={`${keyPrefix}-${index}`}
          style={item.color ? { color: item.color } : undefined}
        >
          {item.text}
        </span>
      ))}
    </div>
  );

  return (
    <section className="chat-live-stream-panel" aria-label="直播弹幕">
      <header className="chat-live-stream-stats">
        <strong>【直播人数 👤：{stream.viewers}】</strong>
        <strong>【直播热度 🔥：{stream.heat}】</strong>
        <strong>【弹幕风向 📊：{stream.trend}】</strong>
      </header>
      {stream.superChat && (
        <div className="chat-live-stream-super-chat">
          <span>【SC {stream.superChat.amount} BY </span>
          <strong style={stream.superChat.color ? { color: stream.superChat.color } : undefined}>
            {stream.superChat.sender}
            {stream.superChat.message ? `：${stream.superChat.message}` : ""}
          </strong>
          <span>】</span>
        </div>
      )}
      {stream.lanes.length > 0 && (
        <div className="chat-live-stream-marquees">
          {stream.lanes.map((items, laneIndex) => {
            const contentLength = items.reduce((total, item) => total + item.text.length, 0);
            const duration = Math.max(16, Math.min(42, contentLength * 0.34));
            return (
              <div
                className="chat-live-stream-marquee"
                aria-label={items.map((item) => item.text).join("，")}
                key={`live-stream-lane-${laneIndex}`}
              >
                <div
                  className="chat-live-stream-marquee-track"
                  style={{ animationDuration: `${duration}s` }}
                >
                  {renderLaneItems(items, `lane-${laneIndex}-primary`)}
                  {renderLaneItems(items, `lane-${laneIndex}-copy`, true)}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </section>
  );
}

function getWorkspaceInfo(
  handle: LocalDirectoryHandle | ElectronWorkspaceHandle | AndroidWorkspaceHandle | PcWorkspaceHandle | null,
) {
  if (!handle) {
    return {
      key: DEFAULT_WORKSPACE_KEY,
      name: DEFAULT_WORKSPACE_NAME,
    };
  }

  if (handle.kind === "electron") {
    return {
      key: handle.path,
      name: handle.name,
      path: handle.path,
    };
  }

  if (handle.kind === "android") {
    return {
      key: `android:${handle.uri}`,
      name: handle.name,
      path: handle.uri,
    };
  }

  if (handle.kind === "pc") {
    return {
      key: `pc:${handle.baseUrl}:${handle.path}`,
      name: handle.name,
      path: handle.path,
    };
  }

  return {
    key: `browser:${handle.name}`,
    name: handle.name,
  };
}

function getChatSenderPersona(
  sender: ChatSenderIdentity | undefined,
  personas: AgentPersona[],
) {
  if (sender?.kind !== "persona" || !sender.personaId) return null;
  return personas.find((persona) => persona.id === sender.personaId) ?? null;
}

function getAssistantMessagePersona(
  message: ChatMessage,
  personas: AgentPersona[],
  fallbackPersona?: AgentPersona,
) {
  return getChatSenderPersona(message.sender, personas) ?? fallbackPersona ?? null;
}

function getChatSenderName(
  sender: ChatSenderIdentity | undefined,
  personas: AgentPersona[],
  userProfile: UserProfile,
) {
  if (sender?.kind === "system") return "系统提示词";

  const senderPersona = getChatSenderPersona(sender, personas);
  if (senderPersona) return senderPersona.name;

  return userProfile.nickname || "User";
}

function getChatSenderAvatarImage(
  sender: ChatSenderIdentity | undefined,
  personas: AgentPersona[],
  userProfile: UserProfile,
) {
  const senderPersona = getChatSenderPersona(sender, personas);
  return senderPersona?.avatarImage || (sender?.kind === "user" ? userProfile.avatarImage : "");
}

function formatFileSize(size: number) {
  if (!Number.isFinite(size) || size <= 0) return "0 B";
  const units = ["B", "KB", "MB", "GB", "TB"];
  let value = size;
  let unitIndex = 0;
  while (value >= 1024 && unitIndex < units.length - 1) {
    value /= 1024;
    unitIndex += 1;
  }
  return `${value >= 10 || unitIndex === 0 ? value.toFixed(0) : value.toFixed(1)} ${units[unitIndex]}`;
}

function uploadCompleteBackupWithProgress(
  file: File,
  onProgress: (loaded: number, total: number) => void,
  onUploadComplete: () => void,
) {
  return new Promise<{ exportedAt?: string }>((resolve, reject) => {
    const request = new XMLHttpRequest();
    request.open("PUT", "/api/app-data/import-complete");
    request.timeout = 10 * 60 * 1000;
    request.setRequestHeader(
      "Content-Type",
      file.name.toLowerCase().endsWith(".zip") ? "application/zip" : "application/json",
    );
    request.upload.onprogress = (event) => {
      const total = event.lengthComputable && event.total > 0 ? event.total : file.size;
      onProgress(event.loaded, total);
    };
    request.upload.onload = () => onUploadComplete();
    request.onload = () => {
      let payload: { error?: string; exportedAt?: string } = {};
      try {
        const parsed = JSON.parse(request.responseText) as unknown;
        if (isObjectRecord(parsed)) {
          payload = {
            error: typeof parsed.error === "string" ? parsed.error : undefined,
            exportedAt: typeof parsed.exportedAt === "string" ? parsed.exportedAt : undefined,
          };
        }
      } catch {
        // The status code below still provides a useful fallback error.
      }
      if (request.status >= 200 && request.status < 300) {
        resolve(payload);
      } else {
        reject(new Error(payload.error || `本地数据服务返回 ${request.status || "未知状态"}`));
      }
    };
    request.onerror = () => reject(new Error("无法连接手机本地数据服务。"));
    request.ontimeout = () => reject(new Error("导入超时，请确认手机剩余存储空间后重试。"));
    request.onabort = () => reject(new Error("导入已中止。"));
    request.send(file);
  });
}

function isTextLikeFile(fileName: string, mimeType: string) {
  const lowerName = fileName.toLowerCase();
  if (mimeType.startsWith("text/")) return true;
  if (
    [
      "application/json",
      "application/xml",
      "application/javascript",
      "application/typescript",
      "application/x-javascript",
      "application/x-typescript",
      "application/x-sh",
      "application/sql",
      "image/svg+xml",
    ].includes(mimeType)
  ) {
    return true;
  }
  return /\.(txt|md|markdown|json|jsonl|csv|tsv|xml|html|htm|css|js|jsx|ts|tsx|mjs|cjs|vue|svelte|py|java|kt|kts|c|cc|cpp|h|hpp|cs|go|rs|php|rb|swift|sh|bat|cmd|ps1|sql|yaml|yml|toml|ini|env|log|svg)$/i.test(
    lowerName,
  );
}

function getDataUrlBase64(dataUrl: string) {
  const commaIndex = dataUrl.indexOf(",");
  return commaIndex >= 0 ? dataUrl.slice(commaIndex + 1) : dataUrl;
}

function canProviderReceiveImageUrl(
  provider: ModelProviderChannel | null | undefined,
  modelId: string,
) {
  const target = `${provider?.name ?? ""} ${provider?.apiBaseUrl ?? ""} ${modelId}`.toLowerCase();
  return /\b(vl|vision|visual|qwen.*vl|qwen3-vl|gpt-4o|gpt-5|gemini|claude|pixtral|llava|internvl|minicpm-v|glm-4v|yi-vl)\b/i.test(
    target,
  );
}

function shouldUseImageRecognitionMcpForAttachments(
  attachments: ChatAttachment[],
  imageRecognitionMcpTool: McpToolDefinition | undefined,
) {
  return Boolean(
    imageRecognitionMcpTool &&
      attachments.some((attachment) => attachment.type.startsWith("image/") && attachment.dataUrl),
  );
}

function isImageRecognitionMcpTool(tool: McpToolDefinition) {
  const target = `${tool.originalName} ${tool.function.name}`.toLowerCase();
  return (
    target.includes("describe-image") ||
    target.includes("analyze_image") ||
    target.includes("analyze-image") ||
    target.includes("describe_image")
  );
}

function findImageRecognitionMcpTool(tools: McpToolDefinition[]) {
  return (
    tools.find((tool) => /^(describe_image|describe-image)$/i.test(tool.originalName)) ??
    tools.find(isImageRecognitionMcpTool)
  );
}

function extractImageRecognitionText(result: unknown) {
  const text = getMcpTextContentItems(result)
    .map((item) => String(item.text ?? "").trim())
    .filter(Boolean)
    .join("\n\n");
  if (!text) return "";

  try {
    const parsed = JSON.parse(text) as unknown;
    if (isObjectRecord(parsed) && typeof parsed.text === "string") {
      return parsed.text.trim() || text;
    }
  } catch {
    // Keep plain text results as-is.
  }

  return text;
}

function buildAttachmentTextBlock(
  attachment: ChatAttachment,
  index: number,
  options: {
    sendImageAttachmentsToProvider?: boolean;
    hasImageRecognitionMcp?: boolean;
  } = {},
) {
  const header = [
    `附件 ${index + 1}: ${attachment.name}`,
    `附件ID: ${attachment.id}`,
    `类型: ${attachment.type || "application/octet-stream"}`,
    `大小: ${attachment.size} bytes (${formatFileSize(attachment.size)})`,
  ].join("\n");

  if (attachment.textContent !== undefined) {
    return `${header}\n内容:\n${attachment.textContent}`;
  }

  if (attachment.type.startsWith("image/")) {
    if (options.sendImageAttachmentsToProvider) {
      return `${header}\n图片已作为 image_url 随消息发送。`;
    }
    if (options.hasImageRecognitionMcp) {
      return `${header}\n当前聊天模型不直接接收 image_url；图片应通过已启用的图像识别 MCP 工具分析。调用图像识别 MCP 时可以用附件ID或文件名作为 image/imageUrl，客户端会映射到图片数据。不要为了识别图片而调用 local_preview_pc_image 或 local_transfer_attachment_file；这些工具只用于用户明确要求查看电脑工作区文件、保存或传输附件。`;
    }
    return `${header}\n当前聊天模型不直接接收 image_url，图片内容没有发送给模型。请切换到视觉模型，或启用图像识别 MCP 后重试。`;
  }

  return `${header}\n这是二进制或未知格式附件，内容没有发送给模型。只有当用户明确要求保存或传输这个附件时，才调用 local_transfer_attachment_file；不要把附件传输当作图片识别或内容分析方式。`;
}

function formatAttachmentPrompt(
  attachments: ChatAttachment[],
  options: {
    sendImageAttachmentsToProvider?: boolean;
    hasImageRecognitionMcp?: boolean;
  } = {},
) {
  if (attachments.length === 0) return "";
  const imageGuidance = options.sendImageAttachmentsToProvider
    ? "图片可按 image_url 分析"
    : options.hasImageRecognitionMcp
      ? "图片应通过已启用的图像识别 MCP 工具分析"
      : "图片不会直接发送给当前文本模型";
  return [
    `用户随消息上传了以下文件。文本附件可直接结合内容回答；${imageGuidance}；二进制或未知格式附件不会把内容发送给模型，保存或传输时必须调用附件/文件传输工具，不要要求用户提供 Base64。`,
    ...attachments.map((attachment, index) => buildAttachmentTextBlock(attachment, index, options)),
  ].join("\n\n");
}

async function maybeAttachReferenceImageForImageModel(
  apiMessages: ChatApiMessage[],
  modelId: string,
): Promise<ChatApiMessage[]> {
  // 图片模型的历史文字和历史图片由服务端统一收集并转成 edits/generations 请求。
  // 这里保留函数入口，避免旧调用点变动，但不再只把“最近一张图”挂到最后用户消息上。
  void modelId;
  return apiMessages;
}

function isImageGenerationModelId(modelId: string): boolean {
  const m = (modelId || "").toLowerCase();
  return (
    m.includes("dall-e") ||
    m.includes("image") ||
    m.includes("gpt-image") ||
    m.includes("stable-diffusion") ||
    m.includes("sd-") ||
    m.includes("midjourney") ||
    m.includes("mj-") ||
    m.includes("flux") ||
    m.includes("civitai")
  );
}

// 从一段 markdown 文本里抽出第一张图片 URL（http(s) / data: / 相对路径 /api/session-images/...）
function extractFirstImageUrlFromMarkdown(textBody: string): string {
  if (!textBody) return "";
  const m = textBody.match(/!\[[^\]]*\]\((https?:\/\/[^)\s]+|data:image\/[^)\s]+|\/api\/session-images\/[^)\s]+)\)/i);
  return m ? m[1] : "";
}

function getImageUrlMimeType(url: string) {
  const cleanUrl = url.split("?")[0]?.toLowerCase() ?? "";
  if (/\.jpe?g$/.test(cleanUrl)) return "image/jpeg";
  if (/\.webp$/.test(cleanUrl)) return "image/webp";
  if (/\.gif$/.test(cleanUrl)) return "image/gif";
  if (/\.svg$/.test(cleanUrl)) return "image/svg+xml";
  return "image/png";
}

function getImageUrlExtension(url: string) {
  const mimeType = getImageUrlMimeType(url);
  if (mimeType === "image/jpeg") return "jpg";
  if (mimeType === "image/webp") return "webp";
  if (mimeType === "image/gif") return "gif";
  if (mimeType === "image/svg+xml") return "svg";
  return "png";
}

function getGeneratedImageAttachmentsFromMessages(messages: ChatMessage[]) {
  const attachments: ChatAttachment[] = [];
  const seen = new Set<string>();
  messages.forEach((message) => {
    if (message.role !== "assistant") return;
    const matches = [...message.content.matchAll(/!\[[^\]]*\]\((https?:\/\/[^)\s]+|data:image\/[^)\s]+|\/api\/session-images\/[^)\s]+)\)/gi)];
    matches.forEach((match, index) => {
      const url = match[1]?.trim();
      if (!url || seen.has(url)) return;
      seen.add(url);
      const mimeType = url.startsWith("data:")
        ? (url.match(/^data:([^;,]+)[;,]/i)?.[1] ?? "image/png")
        : getImageUrlMimeType(url);
      const extension = getMimeExtension(mimeType);
      const id = `generated-image-${attachments.length + 1}`;
      attachments.push({
        id,
        name: `generated-image-${attachments.length + 1}.${extension}`,
        type: mimeType,
        size: url.startsWith("data:") ? estimateBase64Bytes(url) : 0,
        ...(url.startsWith("data:") ? { dataUrl: url } : { downloadUrl: url }),
        createdAt: message.createdAt,
      });
    });
  });
  return attachments;
}

// 把图片 URL 解析成可以传给上游的 image_url（http/data 直接返；相对路径 fetch 到 data URL）
async function resolveImageUrlForUpstream(url: string): Promise<string> {
  if (!url) return "";
  if (/^https?:\/\//i.test(url) || url.startsWith("data:")) return url;
  // 相对路径：fetch 到本地服务，再转 data URL
  if (url.startsWith("/")) {
    try {
      const resp = await fetch(url);
      if (!resp.ok) return "";
      const blob = await resp.blob();
      return await new Promise<string>((resolveReader, rejectReader) => {
        const reader = new FileReader();
        reader.onload = () => resolveReader(typeof reader.result === "string" ? reader.result : "");
        reader.onerror = () => rejectReader(reader.error ?? new Error("读取参考图失败"));
        reader.readAsDataURL(blob);
      });
    } catch {
      return "";
    }
  }
  // 本地绝对路径由后端按会话请求上下文读取并转成 data URL。
  return url;
}

function formatChatMessageForApi(
  message: ChatMessage,
  personas: AgentPersona[],
  userProfile: UserProfile,
  activeChatPersona?: AgentPersona,
  options: {
    sendImageAttachmentsToProvider?: boolean;
    hasImageRecognitionMcp?: boolean;
  } = {},
) {
  if (message.role !== "user") {
    return message.content;
  }

  const sender = message.sender ?? { kind: "user" as const };
  let textContent = message.content;
  if (sender.kind === "system") {
    textContent = `【系统提示词】：${message.content}`;
  } else if (sender.kind === "persona") {
    const senderPersona = getChatSenderPersona(sender, personas);
    if (senderPersona) {
      const identityLabel =
        activeChatPersona && senderPersona.id === activeChatPersona.id
          ? `${senderPersona.name}（你自己）`
          : senderPersona.name;
      textContent = `【${identityLabel}】：${message.content}`;
    }
  }

  const attachments = message.attachments ?? [];
  if (attachments.length === 0) return textContent;

  const textWithAttachments = [textContent, formatAttachmentPrompt(attachments, options)]
    .filter(Boolean)
    .join("\n\n");
  if (!options.sendImageAttachmentsToProvider) return textWithAttachments;

  const imageAttachments = attachments.filter((attachment) =>
    attachment.type.startsWith("image/") && attachment.dataUrl,
  );

  if (imageAttachments.length === 0) return textWithAttachments;

  return [
    { type: "text" as const, text: textWithAttachments || "请分析随消息上传的文件。" },
    ...imageAttachments.map((attachment) => ({
      type: "image_url" as const,
      image_url: { url: attachment.dataUrl ?? "" },
    })),
  ];
}

function buildChatMessageForApi(
  message: ChatMessage,
  personas: AgentPersona[],
  userProfile: UserProfile,
  activeChatPersona: AgentPersona | undefined,
  options: {
    sendImageAttachmentsToProvider?: boolean;
    hasImageRecognitionMcp?: boolean;
  } = {},
): ChatApiMessage {
  const senderPersona =
    message.role === "assistant"
      ? getChatSenderPersona(message.sender, personas)
      : null;
  return {
    role: message.role,
    ...(senderPersona ? { name: getAgentApiName(senderPersona.id) } : {}),
    content: formatChatMessageForApi(
      message,
      personas,
      userProfile,
      activeChatPersona,
      options,
    ),
  };
}

function getChatApiMessageText(message?: ChatApiMessage) {
  if (!message?.content) return "";
  if (typeof message.content === "string") return message.content;
  return message.content
    .filter((part): part is Extract<ChatApiContentPart, { type: "text" }> => part.type === "text")
    .map((part) => part.text)
    .join("\n");
}

function substituteUserNicknameMacro(value: string, nickname: string) {
  const resolvedNickname = nickname.trim() || "用户";
  return value.replace(/{{\s*user\s*}}/gi, () => resolvedNickname);
}

function substituteUserNicknameInApiMessages(
  messages: ChatApiMessage[],
  nickname: string,
) {
  return messages.map((message) => {
    if (typeof message.content === "string") {
      const content = substituteUserNicknameMacro(message.content, nickname);
      return content === message.content ? message : { ...message, content };
    }
    if (!Array.isArray(message.content)) return message;

    let changed = false;
    const content = message.content.map((part) => {
      if (part.type !== "text" || typeof part.text !== "string") return part;
      const text = substituteUserNicknameMacro(part.text, nickname);
      if (text === part.text) return part;
      changed = true;
      return { ...part, text };
    });
    return changed ? { ...message, content } : message;
  });
}

function getReasoningTextFromValue(value: unknown): string {
  if (typeof value === "string") return value.trim();
  if (Array.isArray(value)) {
    return value
      .map((item) => getReasoningTextFromValue(item))
      .filter(Boolean)
      .join("\n\n")
      .trim();
  }
  if (!value || typeof value !== "object") return "";

  const record = value as Record<string, unknown>;
  return [
    record.text,
    record.content,
    record.reasoning,
    record.reasoning_content,
    record.summary,
  ]
    .map(getReasoningTextFromValue)
    .filter(Boolean)
    .join("\n\n")
    .trim();
}

function getChatApiMessageReasoning(message?: ChatApiMessage) {
  if (!message) return "";
  const directReasoning = [
    message.reasoning,
    message.reasoning_content,
    message.reasoning_details,
    message.thinking,
    message.thinking_content,
  ]
    .map(getReasoningTextFromValue)
    .filter(Boolean)
    .join("\n\n")
    .trim();
  if (directReasoning) return directReasoning;

  if (!Array.isArray(message.content)) return "";
  return message.content
    .filter((part) => part.type !== "text" && part.type !== "image_url")
    .map(getReasoningTextFromValue)
    .filter(Boolean)
    .join("\n\n")
    .trim();
}

function getChatCompletionPayloadReasoning(payload: unknown) {
  if (!payload || typeof payload !== "object") return "";
  const record = payload as Record<string, unknown>;
  const choices = Array.isArray(record.choices) ? record.choices : [];
  const choiceRecord =
    choices[0] && typeof choices[0] === "object" && !Array.isArray(choices[0])
      ? (choices[0] as Record<string, unknown>)
      : {};
  const messageReasoning =
    choiceRecord.message && typeof choiceRecord.message === "object"
      ? getChatApiMessageReasoning(choiceRecord.message as ChatApiMessage)
      : "";
  return [
    messageReasoning,
    choiceRecord.reasoning,
    choiceRecord.reasoning_content,
    record.reasoning,
    record.reasoning_content,
    record.output_reasoning,
  ]
    .map(getReasoningTextFromValue)
    .filter(Boolean)
    .join("\n\n")
    .trim();
}

function readFileAsDataUrl(file: File) {
  return new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(typeof reader.result === "string" ? reader.result : "");
    reader.onerror = () => reject(reader.error ?? new Error("文件读取失败"));
    reader.readAsDataURL(file);
  });
}

async function createChatAttachmentFromFile(file: File): Promise<ChatAttachment> {
  const type = file.type || "application/octet-stream";
  const shouldReadDataUrl = type.startsWith("image/");
  const dataUrl = shouldReadDataUrl ? await readFileAsDataUrl(file) : undefined;
  const textContent = isTextLikeFile(file.name, type) ? await file.text() : undefined;

  return {
    id: crypto.randomUUID(),
    name: file.name || "未命名文件",
    type,
    size: file.size,
    ...(dataUrl ? { dataUrl } : {}),
    ...(textContent !== undefined ? { textContent } : {}),
    createdAt: new Date().toISOString(),
  };
}

function stripBase64Prefix(value: string) {
  const trimmedValue = value.trim();
  const commaIndex = trimmedValue.indexOf(",");
  return trimmedValue.startsWith("data:") && commaIndex >= 0
    ? trimmedValue.slice(commaIndex + 1)
    : trimmedValue;
}

function arrayBufferToBase64(buffer: ArrayBuffer) {
  const bytes = new Uint8Array(buffer);
  const chunkSize = 0x8000;
  let binary = "";
  for (let index = 0; index < bytes.length; index += chunkSize) {
    binary += String.fromCharCode(...bytes.subarray(index, index + chunkSize));
  }
  return btoa(binary);
}

function base64ToArrayBuffer(base64Value: string) {
  const cleanBase64 = stripBase64Prefix(base64Value).replace(/\s+/g, "");
  const binary = atob(cleanBase64);
  const bytes = new Uint8Array(binary.length);
  for (let index = 0; index < binary.length; index += 1) {
    bytes[index] = binary.charCodeAt(index);
  }
  return bytes.buffer;
}

async function createImagePreviewDataUrl(blob: Blob, maxSide = 768) {
  const objectUrl = URL.createObjectURL(blob);
  try {
    const image = await new Promise<HTMLImageElement>((resolve, reject) => {
      const nextImage = new Image();
      nextImage.onload = () => resolve(nextImage);
      nextImage.onerror = () => reject(new Error("图片预览加载失败"));
      nextImage.src = objectUrl;
    });
    const scale = Math.min(1, maxSide / Math.max(image.naturalWidth, image.naturalHeight));
    const width = Math.max(1, Math.round(image.naturalWidth * scale));
    const height = Math.max(1, Math.round(image.naturalHeight * scale));
    const canvas = document.createElement("canvas");
    canvas.width = width;
    canvas.height = height;
    const context = canvas.getContext("2d");
    if (!context) throw new Error("无法创建图片预览画布");
    context.fillStyle = "#ffffff";
    context.fillRect(0, 0, width, height);
    context.drawImage(image, 0, 0, width, height);
    return {
      dataUrl: canvas.toDataURL("image/jpeg", 0.78),
      width,
      height,
      originalWidth: image.naturalWidth,
      originalHeight: image.naturalHeight,
    };
  } finally {
    URL.revokeObjectURL(objectUrl);
  }
}

function buildChatSenderContextPrompt(
  messages: ChatMessage[],
  personas: AgentPersona[],
  activeChatPersona?: AgentPersona,
) {
  const personaSenderMessages = messages.filter(
    (message) => message.role === "user" && message.sender?.kind === "persona",
  );
  const hasSystemSender = messages.some(
    (message) => message.role === "user" && message.sender?.kind === "system",
  );

  if (personaSenderMessages.length === 0 && !hasSystemSender) return "";

  const hasSelfSender =
    Boolean(activeChatPersona) &&
    personaSenderMessages.some((message) => message.sender?.personaId === activeChatPersona?.id);
  const personaSenderNames = Array.from(
    new Set(
      personaSenderMessages
        .map((message) => getChatSenderPersona(message.sender, personas)?.name)
        .filter((name): name is string => Boolean(name)),
    ),
  );

  return [
    "发言身份规则：",
    personaSenderNames.length > 0
      ? `- 用户消息中出现的【${personaSenderNames.join("】、【")}】前缀表示该条消息由对应人格 Agent 发出。`
      : "",
    hasSelfSender && activeChatPersona
      ? `- 当消息前缀是【${activeChatPersona.name}（你自己）】时，它表示当前对话人格本人的发言、想法或自我指令；不要把它理解为另一个同名用户。`
      : "",
    hasSystemSender
      ? "- 【系统提示词】前缀表示用户正在以系统指令方式要求当前人格 Agent 调整回复。"
      : "",
  ]
    .filter(Boolean)
    .join("\n");
}

function formatMemoryMessage(
  message: ChatMessage,
  personas: AgentPersona[],
  userProfile: UserProfile,
  activeChatPersona?: AgentPersona,
) {
  const assistantPersona = getAssistantMessagePersona(
    message,
    personas,
    activeChatPersona,
  );
  const speaker =
    message.role === "assistant"
      ? assistantPersona?.name ?? "AI"
      : getChatSenderName(message.sender, personas, userProfile);
  return `${speaker}：${message.content.trim()}`;
}

function buildPersonaMemoryPrompt(
  sessions: ChatSession[],
  activeSessionId: string,
  persona: AgentPersona | undefined,
  personas: AgentPersona[],
  userProfile: UserProfile,
) {
  if (!persona) return "";

  const memorySessions = sessions.filter(
    (session) =>
      session.id !== activeSessionId &&
      session.memoryPersonaIds.includes(persona.id) &&
      session.messages.some((message) => message.content.trim()),
  );

  if (memorySessions.length === 0) return "";

  return [
    `以下是你可参考的长期会话记忆，仅用于延续与「${persona.name}」相关的人格、关系和上下文；不要逐字复述，除非用户要求：`,
    ...memorySessions.map((session) =>
      [
        `## ${session.title || "未命名会话"} / ${session.workspaceName}`,
        ...session.messages
          .filter((message) => message.content.trim())
          .map((message) => `- ${formatMemoryMessage(message, personas, userProfile, persona)}`),
      ].join("\n"),
    ),
  ].join("\n\n");
}

function getAvailableLocalToolDefinitions(
  handle: LocalDirectoryHandle | ElectronWorkspaceHandle | AndroidWorkspaceHandle | PcWorkspaceHandle | null,
) {
  if (!handle) return [];
  if (handle.kind === "electron") {
    return localFileToolDefinitions.filter(
      (tool) =>
        tool.function.name !== "local_transfer_file" &&
        tool.function.name !== "local_send_pc_file",
    );
  }

  if (handle.kind === "android") {
    const androidUnsupportedTools = new Set([
      "local_rename_path",
      "local_run_script",
      "local_run_command",
      "local_git_status",
      "local_git_diff",
      "project_detect_stack",
      "project_find_symbols",
      "project_search_regex",
      "project_read_package_json",
      "project_todo_scan",
    ]);
    return localFileToolDefinitions.filter(
      (tool) => !androidUnsupportedTools.has(tool.function.name),
    );
  }

  if (handle.kind === "pc") {
    const pcUnsupportedTools = new Set([
      "local_rename_path",
      "local_run_script",
      "local_run_command",
      "local_git_status",
      "local_git_diff",
      "project_detect_stack",
      "project_find_symbols",
      "project_search_regex",
      "project_read_package_json",
      "project_todo_scan",
    ]);
    return localFileToolDefinitions.filter(
      (tool) => !pcUnsupportedTools.has(tool.function.name),
    );
  }

  const browserUnsupportedTools = new Set([
    "local_rename_path",
    "local_run_script",
    "local_run_command",
    "local_git_status",
    "local_git_diff",
    "local_transfer_file",
    "local_send_pc_file",
  ]);
  return localFileToolDefinitions.filter(
    (tool) => !browserUnsupportedTools.has(tool.function.name),
  );
}

