function looksLikeChatPresetTimeHeader(line: string) {
  const leadingHeader = line.match(/^[\[【（(][^\]】）)\r\n]{6,240}[\]】）)]/)?.[0] ?? "";
  return /(?:年|月|日|星期|周|\d{1,2}[:：,]\d{2}|天气|地点)/.test(
    leadingHeader,
  );
}

function reconcileChatContinuation(existingContent: string, rawContent: string) {
  if (!rawContent) return { content: "", restarted: false };
  if (rawContent.startsWith(existingContent)) {
    const continuation = rawContent.slice(existingContent.length);
    return {
      content: continuation,
      restarted: !continuation,
    };
  }

  const maximumAnchorLength = Math.min(600, existingContent.length);
  for (
    let anchorLength = maximumAnchorLength;
    anchorLength >= 48;
    anchorLength = Math.floor(anchorLength * 0.75)
  ) {
    const breakpointAnchor = existingContent.slice(-anchorLength);
    const anchorIndex = rawContent.indexOf(breakpointAnchor);
    if (anchorIndex < 0) continue;
    const continuation = rawContent.slice(anchorIndex + breakpointAnchor.length);
    return {
      content: continuation,
      restarted: !continuation,
    };
  }

  const normalizedExisting = existingContent.trimStart();
  const normalizedRaw = rawContent.trimStart();
  let commonPrefixLength = 0;
  const maximumPrefixLength = Math.min(normalizedExisting.length, normalizedRaw.length);
  while (
    commonPrefixLength < maximumPrefixLength &&
    normalizedExisting[commonPrefixLength] === normalizedRaw[commonPrefixLength]
  ) {
    commonPrefixLength += 1;
  }
  const commonPrefixThreshold = Math.min(
    120,
    Math.max(24, Math.floor(normalizedExisting.length * 0.25)),
  );
  const existingFirstLine = normalizedExisting.split(/\r?\n/, 1)[0]?.trim() ?? "";
  const rawFirstLine = normalizedRaw.split(/\r?\n/, 1)[0]?.trim() ?? "";
  const repeatsExistingFirstLine =
    existingFirstLine.length >= 12 && normalizedRaw.startsWith(existingFirstLine);
  const repeatsExistingOpening =
    normalizedExisting.length >= 48 &&
    normalizedRaw.indexOf(normalizedExisting.slice(0, Math.min(160, normalizedExisting.length))) >=
      0;
  const repeatsPresetTimeHeader =
    looksLikeChatPresetTimeHeader(existingFirstLine) &&
    looksLikeChatPresetTimeHeader(rawFirstLine);

  if (
    commonPrefixLength >= commonPrefixThreshold ||
    repeatsExistingFirstLine ||
    repeatsExistingOpening ||
    repeatsPresetTimeHeader
  ) {
    return { content: "", restarted: true };
  }

  return { content: rawContent, restarted: false };
}

function createChatContinuationStreamGate(
  existingContent: string,
  onAcceptedDelta: (delta: string) => void,
) {
  const normalizedExisting = existingContent.trimStart();
  const existingFirstLine = normalizedExisting.split(/\r?\n/, 1)[0]?.trim() ?? "";
  const commonPrefixThreshold = Math.min(
    120,
    Math.max(24, Math.floor(normalizedExisting.length * 0.25)),
  );
  let state: "pending" | "streaming" | "restarted" = "pending";
  let bufferedContent = "";
  let acceptedContent = "";

  const accept = (content: string) => {
    if (!content) return;
    acceptedContent += content;
    onAcceptedDelta(content);
  };

  const evaluateBufferedContent = () => {
    const normalizedBuffered = bufferedContent.trimStart();
    if (!normalizedBuffered) return;

    if (/^[\[【（(]/.test(normalizedBuffered)) {
      const rawFirstLine = normalizedBuffered.split(/\r?\n/, 1)[0]?.trim() ?? "";
      const hasClosedLeadingHeader = /^[\[【（(][^\]】）)\r\n]{0,240}[\]】）)]/.test(
        rawFirstLine,
      );
      if (!hasClosedLeadingHeader && normalizedBuffered.length < 240) return;
      if (
        looksLikeChatPresetTimeHeader(existingFirstLine) &&
        looksLikeChatPresetTimeHeader(rawFirstLine)
      ) {
        state = "restarted";
        return;
      }
    }

    if (normalizedExisting.startsWith(normalizedBuffered)) return;
    if (normalizedBuffered.startsWith(normalizedExisting)) {
      state = "streaming";
      const continuation = normalizedBuffered.slice(normalizedExisting.length);
      bufferedContent = "";
      accept(continuation);
      return;
    }

    let commonPrefixLength = 0;
    const maximumPrefixLength = Math.min(
      normalizedExisting.length,
      normalizedBuffered.length,
    );
    while (
      commonPrefixLength < maximumPrefixLength &&
      normalizedExisting[commonPrefixLength] === normalizedBuffered[commonPrefixLength]
    ) {
      commonPrefixLength += 1;
    }
    if (commonPrefixLength >= commonPrefixThreshold) {
      state = "restarted";
      return;
    }

    state = "streaming";
    const initialContent = bufferedContent;
    bufferedContent = "";
    accept(initialContent);
  };

  return {
    push(delta: string) {
      if (!delta || state === "restarted") return;
      if (state === "streaming") {
        accept(delta);
        return;
      }
      bufferedContent += delta;
      evaluateBufferedContent();
    },
    finish(rawContent: string) {
      if (state === "streaming") {
        return { content: acceptedContent, restarted: false };
      }
      const reconciled = reconcileChatContinuation(existingContent, rawContent);
      if (!reconciled.restarted && reconciled.content) accept(reconciled.content);
      return {
        content: acceptedContent,
        restarted: reconciled.restarted,
      };
    },
  };
}

function createChatAbortError() {
  return new DOMException("AI 输出已停止。", "AbortError");
}

function isChatAbortError(error: unknown) {
  if (error instanceof DOMException && error.name === "AbortError") return true;
  return error instanceof Error && error.name === "AbortError";
}

function throwIfChatAborted(signal?: AbortSignal) {
  if (signal?.aborted) throw createChatAbortError();
}

type StreamingWordSegment = {
  segment: string;
  index: number;
  isWordLike: boolean;
};

function createStreamingWordWriter(
  onWord: (word: string) => void,
  signal?: AbortSignal,
) {
  const segmenter =
    typeof Intl.Segmenter === "function"
      ? new Intl.Segmenter(undefined, { granularity: "word" })
      : null;
  let pendingText = "";
  let queuedWords: string[] = [];
  let timerId: number | undefined;
  let finished = false;
  let cancelled = false;
  let finishPromise: Promise<void> | null = null;
  let resolveFinish: (() => void) | null = null;
  let removeActivityListeners: () => void = () => undefined;

  const segmentText = (text: string): StreamingWordSegment[] => {
    if (segmenter) {
      return Array.from(segmenter.segment(text), (item) => ({
        segment: item.segment,
        index: item.index,
        isWordLike: item.isWordLike === true,
      }));
    }

    return Array.from(text.matchAll(/\s+|[\p{L}\p{N}_]+|./gu), (match) => ({
      segment: match[0],
      index: match.index ?? 0,
      isWordLike: /^[\p{L}\p{N}_]+$/u.test(match[0]),
    }));
  };

  const resolveWhenIdle = () => {
    if (!finished || timerId !== undefined || queuedWords.length > 0 || pendingText) return;
    removeActivityListeners();
    signal?.removeEventListener("abort", cancel);
    resolveFinish?.();
    resolveFinish = null;
  };

  const shouldAnimateWords = () =>
    typeof document === "undefined" ||
    (document.visibilityState === "visible" && document.hasFocus());

  const flushImmediately = () => {
    if (timerId !== undefined) window.clearTimeout(timerId);
    timerId = undefined;
    const content = `${queuedWords.join("")}${pendingText}`;
    queuedWords = [];
    pendingText = "";
    if (content) onWord(content);
    resolveWhenIdle();
  };

  const scheduleNextWord = () => {
    if (cancelled || timerId !== undefined || queuedWords.length === 0) {
      resolveWhenIdle();
      return;
    }
    if (!shouldAnimateWords()) {
      flushImmediately();
      return;
    }

    const delay = queuedWords.length > 120 ? 8 : queuedWords.length > 40 ? 16 : 32;
    timerId = window.setTimeout(() => {
      timerId = undefined;
      const word = queuedWords.shift();
      if (word) onWord(word);
      scheduleNextWord();
    }, delay);
  };

  const enqueueStableWords = (flushAll: boolean) => {
    if (!pendingText) return;
    if (!shouldAnimateWords()) {
      flushImmediately();
      return;
    }
    const segments = segmentText(pendingText);
    const lastSegment = segments.at(-1);
    const stableEnd =
      !flushAll &&
      lastSegment?.isWordLike &&
      lastSegment.index + lastSegment.segment.length === pendingText.length
        ? lastSegment.index
        : pendingText.length;
    if (stableEnd <= 0) return;

    const stableSegments = segments.filter(
      (item) => item.index + item.segment.length <= stableEnd,
    );
    const words: string[] = [];
    stableSegments.forEach((item) => {
      if (!item.isWordLike && words.length > 0) {
        words[words.length - 1] += item.segment;
      } else {
        words.push(item.segment);
      }
    });
    queuedWords.push(...words.filter(Boolean));
    pendingText = pendingText.slice(stableEnd);
    scheduleNextWord();
  };

  if (typeof document !== "undefined") {
    const handleActivityChange = () => {
      if (cancelled) return;
      if (shouldAnimateWords()) scheduleNextWord();
      else flushImmediately();
    };
    document.addEventListener("visibilitychange", handleActivityChange);
    window.addEventListener("focus", handleActivityChange);
    window.addEventListener("blur", handleActivityChange);
    removeActivityListeners = () => {
      document.removeEventListener("visibilitychange", handleActivityChange);
      window.removeEventListener("focus", handleActivityChange);
      window.removeEventListener("blur", handleActivityChange);
      removeActivityListeners = () => undefined;
    };
  }

  const cancel = () => {
    if (cancelled) return;
    cancelled = true;
    if (timerId !== undefined) window.clearTimeout(timerId);
    timerId = undefined;
    queuedWords = [];
    pendingText = "";
    removeActivityListeners();
    resolveFinish?.();
    resolveFinish = null;
    signal?.removeEventListener("abort", cancel);
  };

  signal?.addEventListener("abort", cancel, { once: true });

  return {
    push(delta: string) {
      if (!delta || finished || cancelled) return;
      pendingText += delta;
      enqueueStableWords(false);
    },
    finish() {
      if (cancelled) return Promise.resolve();
      if (!finished) {
        finished = true;
        enqueueStableWords(true);
      }
      if (timerId === undefined && queuedWords.length === 0 && !pendingText) {
        removeActivityListeners();
        signal?.removeEventListener("abort", cancel);
        return Promise.resolve();
      }
      if (!finishPromise) {
        finishPromise = new Promise<void>((resolve) => {
          resolveFinish = () => {
            signal?.removeEventListener("abort", cancel);
            resolve();
          };
        });
      }
      return finishPromise;
    },
    cancel,
  };
}

async function readChatStream(
  response: Response,
  onDelta: (delta: string) => void,
  onReasoningDelta: (delta: string) => void = () => undefined,
  signal?: AbortSignal,
) {
  throwIfChatAborted(signal);

  if (!response.ok) {
    const errorText = await response.text();
    try {
      const payload = JSON.parse(errorText) as { error?: string | { message?: string } };
      const errorMessage =
        typeof payload.error === "string" ? payload.error : payload.error?.message;
      throw new Error(errorMessage ? `请求失败：${response.status} ${errorMessage}` : `请求失败：${response.status}`);
    } catch (error) {
      if (error instanceof SyntaxError) {
        throw new Error(`请求失败：${response.status} ${errorText}`);
      }
      throw error;
    }
  }

  const contentType = response.headers.get("content-type") || "";
  if (!/text\/event-stream/i.test(contentType)) {
    const text = await response.text();
    let payload: unknown;
    try {
      payload = JSON.parse(text);
    } catch {
      throw new Error("收到的不是有效的流式响应。");
    }
    const streamContent = extractStreamContent(payload);
    if (streamContent.content) onDelta(streamContent.content);
    if (streamContent.reasoning) onReasoningDelta(streamContent.reasoning);
    return {
      content: streamContent.content,
      reasoning: streamContent.reasoning,
      toolCalls: streamContent.toolCalls ?? [],
      finishReason: streamContent.finishReason ?? "",
    };
  }

  if (!response.body) throw new Error("流式响应为空");

  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  let buffer = "";
  let fullContent = "";
  let fullReasoning = "";
  let finishReason = "";
  const toolCallsByIndex = new Map<number, ChatToolCall>();

  const applyToolCallDeltas = (deltas: ChatToolCallDelta[]) => {
    deltas.forEach((delta, fallbackIndex) => {
      const index = Number.isFinite(delta.index) ? Number(delta.index) : fallbackIndex;
      const current = toolCallsByIndex.get(index) ?? {
        id: delta.id || `stream-tool-call-${index}`,
        type: "function" as const,
        function: { name: "", arguments: "" },
      };
      toolCallsByIndex.set(index, {
        id: delta.id || current.id,
        type: "function",
        function: {
          name: appendStreamToolFragment(current.function.name, delta.function?.name ?? ""),
          arguments: appendStreamToolFragment(
            current.function.arguments,
            delta.function?.arguments ?? "",
          ),
        },
      });
    });
  };

  const applyCompleteToolCalls = (toolCalls: ChatToolCall[]) => {
    toolCalls.forEach((toolCall, index) => toolCallsByIndex.set(index, toolCall));
  };

  while (true) {
    throwIfChatAborted(signal);
    const { done, value } = await reader.read();
    throwIfChatAborted(signal);
    if (done) break;

    buffer += decoder.decode(value, { stream: true });
    const chunks = buffer.split("\n\n");
    buffer = chunks.pop() ?? "";

    for (const chunk of chunks) {
      const dataLines = chunk
        .split("\n")
        .map((line) => line.trim())
        .filter((line) => line.startsWith("data:"))
        .map((line) => line.slice(5).trim());

      for (const data of dataLines) {
        if (!data || data === "[DONE]") continue;

        try {
          const streamContent = extractStreamContent(JSON.parse(data));
          if (streamContent.finishReason) finishReason = streamContent.finishReason;
          if (streamContent.toolCallDeltas) {
            applyToolCallDeltas(streamContent.toolCallDeltas);
          }
          if (streamContent.toolCalls) {
            applyCompleteToolCalls(streamContent.toolCalls);
          }
          if (streamContent.reasoning) {
            if (streamContent.mode === "delta") {
              fullReasoning += streamContent.reasoning;
              onReasoningDelta(streamContent.reasoning);
            } else if (streamContent.reasoning.startsWith(fullReasoning)) {
              const reasoningDelta = streamContent.reasoning.slice(fullReasoning.length);
              fullReasoning = streamContent.reasoning;
              if (reasoningDelta) onReasoningDelta(reasoningDelta);
            } else {
              fullReasoning = streamContent.reasoning;
            }
          }
          if (!streamContent.content) continue;

          if (streamContent.mode === "delta") {
            fullContent += streamContent.content;
            onDelta(streamContent.content);
            continue;
          }

          if (streamContent.content.startsWith(fullContent)) {
            const delta = streamContent.content.slice(fullContent.length);
            fullContent = streamContent.content;
            if (delta) onDelta(delta);
          } else {
            fullContent = streamContent.content;
          }
        } catch {
          // Ignore malformed event frames from non-standard providers.
        }
      }
    }
  }

  return {
    content: fullContent,
    reasoning: fullReasoning,
    finishReason,
    toolCalls: Array.from(toolCallsByIndex.entries())
      .sort(([left], [right]) => left - right)
      .map(([, toolCall]) => toolCall)
      .filter((toolCall) => toolCall.function.name),
  };
}

function splitLocalPath(path = "") {
  const normalizedPath = path.replace(/\\/g, "/").replace(/^\/+/, "");
  const parts = normalizedPath.split("/").filter(Boolean);

  if (parts.some((part) => part === "." || part === "..")) {
    throw new Error("路径不能包含 . 或 ..");
  }

  return parts;
}

async function getLocalDirectory(
  root: LocalDirectoryHandle,
  parts: string[],
  create = false,
) {
  let currentDirectory = root;

  for (const part of parts) {
    currentDirectory = await currentDirectory.getDirectoryHandle(part, { create });
  }

  return currentDirectory;
}

async function getLocalParentDirectory(
  root: LocalDirectoryHandle,
  path: string,
  create = false,
) {
  const parts = splitLocalPath(path);
  const name = parts.pop();
  if (!name) throw new Error("缺少文件或目录名称");

  return {
    directory: await getLocalDirectory(root, parts, create),
    name,
  };
}

async function listLocalFiles(
  root: LocalDirectoryHandle,
  path = "",
  recursive = true,
  limit = 240,
) {
  const startDirectory = await getLocalDirectory(root, splitLocalPath(path));
  const results: Array<{ path: string; kind: "file" | "directory" }> = [];

  async function visit(directory: LocalDirectoryHandle, basePath: string) {
    if (results.length >= limit) return;

    for await (const entry of directory.values()) {
      const entryPath = basePath ? `${basePath}/${entry.name}` : entry.name;
      results.push({ path: entryPath, kind: entry.kind });

      if (entry.kind === "directory" && recursive && results.length < limit) {
        await visit(entry, entryPath);
      }

      if (results.length >= limit) return;
    }
  }

  await visit(startDirectory, path.replace(/\\/g, "/").replace(/^\/+|\/+$/g, ""));
  return results;
}

async function readLocalTextFile(root: LocalDirectoryHandle, path: string) {
  const { directory, name } = await getLocalParentDirectory(root, path);
  const fileHandle = await directory.getFileHandle(name);
  const file = await fileHandle.getFile();
  return file.text();
}

async function readLocalBinaryFile(root: LocalDirectoryHandle, path: string) {
  const { directory, name } = await getLocalParentDirectory(root, path);
  const fileHandle = await directory.getFileHandle(name);
  const file = await fileHandle.getFile();
  return {
    path,
    name: file.name,
    type: file.type || "application/octet-stream",
    size: file.size,
    base64: arrayBufferToBase64(await file.arrayBuffer()),
  };
}

async function readLocalTextFileRange(
  root: LocalDirectoryHandle,
  path: string,
  startLine = 1,
  endLine = startLine + 120,
) {
  const content = await readLocalTextFile(root, path);
  const lines = content.replace(/\r\n/g, "\n").split("\n");
  const safeStartLine = Math.max(1, Math.floor(startLine));
  const safeEndLine = Math.min(lines.length, Math.max(safeStartLine, Math.floor(endLine)));

  return {
    path,
    startLine: safeStartLine,
    endLine: safeEndLine,
    totalLines: lines.length,
    content: lines.slice(safeStartLine - 1, safeEndLine).join("\n"),
  };
}

async function getLocalFileInfo(root: LocalDirectoryHandle, path: string) {
  const parts = splitLocalPath(path);

  if (parts.length === 0) {
    return {
      path: "",
      kind: "directory",
      name: root.name,
    };
  }

  const { directory, name } = await getLocalParentDirectory(root, path);

  try {
    const fileHandle = await directory.getFileHandle(name);
    const file = await fileHandle.getFile();
    return {
      path,
      kind: "file",
      name,
      size: file.size,
      type: file.type,
      modifiedAt: new Date(file.lastModified).toISOString(),
    };
  } catch {
    const directoryHandle = await directory.getDirectoryHandle(name);
    return {
      path,
      kind: "directory",
      name: directoryHandle.name,
    };
  }
}

async function writeLocalTextFile(root: LocalDirectoryHandle, path: string, content: string) {
  const { directory, name } = await getLocalParentDirectory(root, path, true);
  const fileHandle = await directory.getFileHandle(name, { create: true });
  const writable = await fileHandle.createWritable();
  await writable.write(content);
  await writable.close();
}

async function writeLocalBinaryFile(root: LocalDirectoryHandle, path: string, base64: string) {
  const bytes = base64ToArrayBuffer(base64);
  const { directory, name } = await getLocalParentDirectory(root, path, true);
  const fileHandle = await directory.getFileHandle(name, { create: true });
  const writable = await fileHandle.createWritable();
  await writable.write(bytes);
  await writable.close();
  return bytes.byteLength;
}

async function createLocalDirectory(root: LocalDirectoryHandle, path: string) {
  await getLocalDirectory(root, splitLocalPath(path), true);
  return { ok: true, path, operation: "mkdir" };
}

async function editLocalTextFile(
  root: LocalDirectoryHandle,
  path: string,
  findText: string,
  replaceText: string,
) {
  if (!findText) throw new Error("find 不能为空");
  const originalContent = await readLocalTextFile(root, path);
  if (!originalContent.includes(findText)) {
    throw new Error("没有找到要替换的文本");
  }

  const nextContent = originalContent.split(findText).join(replaceText);
  await writeLocalTextFile(root, path, nextContent);
  return {
    replacements: originalContent.split(findText).length - 1,
    bytes: new Blob([nextContent]).size,
  };
}

async function searchLocalFiles(
  root: LocalDirectoryHandle,
  query: string,
  path = "",
  includeContent = true,
) {
  if (!query.trim()) throw new Error("query 不能为空");

  const entries = await listLocalFiles(root, path, true, 320);
  const normalizedQuery = query.toLowerCase();
  const matches: Array<{ path: string; match: "name" | "content"; preview?: string }> = [];

  for (const entry of entries) {
    if (entry.kind !== "file") continue;

    if (entry.path.toLowerCase().includes(normalizedQuery)) {
      matches.push({ path: entry.path, match: "name" });
      continue;
    }

    if (!includeContent) continue;

    try {
      const content = await readLocalTextFile(root, entry.path);
      const matchIndex = content.toLowerCase().indexOf(normalizedQuery);
      if (matchIndex >= 0) {
        matches.push({
          path: entry.path,
          match: "content",
          preview: content.slice(Math.max(0, matchIndex - 60), matchIndex + query.length + 120),
        });
      }
    } catch {
      // Binary or unreadable files are skipped for content search.
    }

    if (matches.length >= 80) break;
  }

  return matches;
}

function isLikelyTextPath(path: string) {
  return /\.(cjs|css|csv|env|html|js|json|jsx|md|mjs|scss|ts|tsx|txt|xml|yaml|yml)$/i.test(path);
}

async function readLocalPackageJson(root: LocalDirectoryHandle) {
  const content = await readLocalTextFile(root, "package.json");
  return JSON.parse(content) as {
    name?: string;
    scripts?: Record<string, string>;
    dependencies?: Record<string, string>;
    devDependencies?: Record<string, string>;
  };
}

async function detectLocalProjectStack(root: LocalDirectoryHandle) {
  const files = await listLocalFiles(root, "", true, 900);
  const filePaths = new Set(files.map((entry) => entry.path));
  let packageJson: Awaited<ReturnType<typeof readLocalPackageJson>> | null = null;

  try {
    packageJson = await readLocalPackageJson(root);
  } catch {
    packageJson = null;
  }

  const dependencies = {
    ...(packageJson?.dependencies ?? {}),
    ...(packageJson?.devDependencies ?? {}),
  };
  const dependencyNames = new Set(Object.keys(dependencies));
  const frameworks = [
    dependencyNames.has("react") ? "React" : "",
    dependencyNames.has("vite") ? "Vite" : "",
    dependencyNames.has("electron") ? "Electron" : "",
    dependencyNames.has("next") ? "Next.js" : "",
    dependencyNames.has("vue") ? "Vue" : "",
    dependencyNames.has("svelte") ? "Svelte" : "",
    dependencyNames.has("typescript") || filePaths.has("tsconfig.json") ? "TypeScript" : "",
  ].filter(Boolean);
  const packageManager = filePaths.has("pnpm-lock.yaml")
    ? "pnpm"
    : filePaths.has("yarn.lock")
      ? "yarn"
      : filePaths.has("package-lock.json")
        ? "npm"
        : "unknown";

  return {
    packageManager,
    frameworks,
    scripts: packageJson?.scripts ?? {},
    configFiles: Array.from(filePaths).filter((path) =>
      /^(package\.json|tsconfig.*\.json|vite\.config\.[cm]?[jt]s|next\.config\.[cm]?[jt]s|electron\/|src\/)/.test(path),
    ).slice(0, 120),
  };
}

async function searchLocalRegex(
  root: LocalDirectoryHandle,
  pattern: string,
  path = "",
  flags = "",
  maxMatches = 80,
) {
  if (!pattern.trim()) throw new Error("pattern 不能为空");
  const safeFlags = Array.from(new Set(`${flags.replace(/[^imsu]/g, "")}g`)).join("");
  const regex = new RegExp(pattern, safeFlags);
  const entries = await listLocalFiles(root, path, true, 700);
  const matches: Array<{ path: string; line: number; column: number; text: string }> = [];

  for (const entry of entries) {
    if (entry.kind !== "file" || !isLikelyTextPath(entry.path)) continue;

    try {
      const content = await readLocalTextFile(root, entry.path);
      const lines = content.replace(/\r\n/g, "\n").split("\n");
      for (let lineIndex = 0; lineIndex < lines.length; lineIndex += 1) {
        regex.lastIndex = 0;
        const match = regex.exec(lines[lineIndex]);
        if (!match) continue;
        matches.push({
          path: entry.path,
          line: lineIndex + 1,
          column: match.index + 1,
          text: lines[lineIndex].slice(0, 240),
        });
        if (matches.length >= maxMatches) return matches;
      }
    } catch {
      // Skip binary or unreadable files.
    }
  }

  return matches;
}

async function scanLocalTodos(
  root: LocalDirectoryHandle,
  path = "",
  maxMatches = 120,
) {
  return searchLocalRegex(root, "\\b(TODO|FIXME|BUG|HACK)\\b[:：]?.*", path, "i", maxMatches);
}

async function findLocalSymbols(
  root: LocalDirectoryHandle,
  query = "",
  path = "",
  maxMatches = 120,
) {
  const entries = await listLocalFiles(root, path, true, 900);
  const normalizedQuery = query.trim().toLowerCase();
  const symbolPattern =
    /^\s*(?:export\s+)?(?:default\s+)?(?:(async)\s+)?(?:(function|class|interface|type|enum)\s+([A-Za-z_$][\w$]*)|(const|let|var)\s+([A-Za-z_$][\w$]*)|([A-Za-z_$][\w$]*)\s*[:=]\s*(?:async\s*)?(?:function\s*)?\()/;
  const symbols: Array<{ path: string; line: number; kind: string; name: string; text: string }> = [];

  for (const entry of entries) {
    if (entry.kind !== "file" || !isLikelyTextPath(entry.path)) continue;

    try {
      const content = await readLocalTextFile(root, entry.path);
      const lines = content.replace(/\r\n/g, "\n").split("\n");

      for (let lineIndex = 0; lineIndex < lines.length; lineIndex += 1) {
        const line = lines[lineIndex];
        const match = symbolPattern.exec(line);
        if (!match) continue;

        const kind = match[2] ?? match[4] ?? "function";
        const name = match[3] ?? match[5] ?? match[6] ?? "";
        if (!name) continue;

        if (
          normalizedQuery &&
          !name.toLowerCase().includes(normalizedQuery) &&
          !line.toLowerCase().includes(normalizedQuery)
        ) {
          continue;
        }

        symbols.push({
          path: entry.path,
          line: lineIndex + 1,
          kind,
          name,
          text: line.trim().slice(0, 240),
        });
        if (symbols.length >= maxMatches) return symbols;
      }
    } catch {
      // Skip binary or unreadable files.
    }
  }

  return symbols;
}

